import type { Question } from "./quizQuestions";

export const cytologyQuestions: Question[] = [
  // =============================================
  // CITOLOGIA (896-995) — 100 questões
  // Fontes: Alberts et al., Biologia Molecular da Célula, 7ª ed.; Junqueira & Carneiro, Biologia Celular e Molecular, 10ª ed.; Lodish et al., Molecular Cell Biology, 9th ed.
  // =============================================

  // --- MEMBRANA PLASMÁTICA (1-15) ---
  { id: 896, topic: "Citologia", question: "O modelo do mosaico fluido da membrana plasmática foi proposto por:", options: ["Watson e Crick", "Singer e Nicolson", "Schleiden e Schwann", "Robert Hooke"], correctIndex: 1, explanation: "Singer e Nicolson (1972) propuseram o modelo do mosaico fluido: bicamada lipídica fluida com proteínas integrais e periféricas distribuídas assimetricamente." },
  { id: 897, topic: "Citologia", question: "Os fosfolipídios da membrana plasmática são moléculas:", options: ["Apolares", "Anfipáticas (cabeça polar + caudas apolares)", "Totalmente hidrofílicas", "Exclusivamente lipídicas"], correctIndex: 1, explanation: "Os fosfolipídios são anfipáticos: cabeça hidrofílica (grupo fosfato + álcool) voltada para o meio aquoso e caudas hidrofóbicas (ácidos graxos) no interior da bicamada." },
  { id: 898, topic: "Citologia", question: "O colesterol na membrana plasmática tem como principal função:", options: ["Servir como receptor hormonal", "Regular a fluidez da membrana, impedindo cristalização e fluidez excessiva", "Transportar íons", "Gerar energia"], correctIndex: 1, explanation: "O colesterol se intercala entre fosfolipídios: em altas temperaturas reduz a fluidez; em baixas temperaturas impede o empacotamento (cristalização). Age como tampão de fluidez." },
  { id: 899, topic: "Citologia", question: "As proteínas integrais (intrínsecas) da membrana:", options: ["Estão fracamente associadas à superfície", "Atravessam total ou parcialmente a bicamada lipídica", "São exclusivamente enzimáticas", "Nunca formam canais"], correctIndex: 1, explanation: "Proteínas integrais possuem domínios transmembranares hidrofóbicos que as ancoram na bicamada. Podem ser de passagem única (single-pass) ou múltipla (multi-pass), formando canais, receptores e transportadores." },
  { id: 900, topic: "Citologia", question: "O glicocálix é formado por:", options: ["Lipídios neutros", "Cadeias de oligossacarídeos ligados a proteínas e lipídios na face EXTERNA da membrana", "Proteínas citoplasmáticas", "DNA mitocondrial"], correctIndex: 1, explanation: "O glicocálix é composto por glicoproteínas e glicolipídios com cadeias de carboidratos voltadas para o meio extracelular. Funções: proteção, reconhecimento celular, adesão, determinação de grupos sanguíneos ABO." },
  { id: 901, topic: "Citologia", question: "O transporte ativo primário pela Na⁺/K⁺-ATPase move:", options: ["3 Na⁺ para dentro e 2 K⁺ para fora", "3 Na⁺ para fora e 2 K⁺ para dentro da célula", "Igual número de Na⁺ e K⁺", "Apenas Na⁺"], correctIndex: 1, explanation: "A bomba Na⁺/K⁺-ATPase é eletrogênica: bombeia 3 Na⁺ para fora e 2 K⁺ para dentro, usando 1 ATP por ciclo. Mantém o gradiente eletroquímico e o potencial de repouso (~-70mV)." },
  { id: 902, topic: "Citologia", question: "A osmose é definida como:", options: ["Transporte ativo de solutos", "Passagem de água por membrana semipermeável do meio menos concentrado para o mais concentrado", "Difusão de gases", "Endocitose de líquidos"], correctIndex: 1, explanation: "Osmose: fluxo de água através de membrana semipermeável a favor do gradiente osmótico (do hipotônico para o hipertônico). Mediada por aquaporinas nos tecidos biológicos." },
  { id: 903, topic: "Citologia", question: "A endocitose mediada por receptor utiliza principalmente vesículas revestidas por:", options: ["Actina", "Clatrina", "Miosina", "Colágeno"], correctIndex: 1, explanation: "A endocitose mediada por receptor usa fossas revestidas por clatrina que se invaginam formando vesículas. Exemplo clássico: captação de LDL pelo receptor de LDL (defeito → hipercolesterolemia familiar)." },
  { id: 904, topic: "Citologia", question: "A pinocitose é a endocitose de:", options: ["Partículas sólidas grandes", "Líquidos e solutos dissolvidos ('beber celular')", "Bactérias", "Organelas danificadas"], correctIndex: 1, explanation: "Pinocitose: ingestão de fluido extracelular com solutos dissolvidos em pequenas vesículas. Ocorre em praticamente todas as células, especialmente células endoteliais (transcitose)." },
  { id: 905, topic: "Citologia", question: "As aquaporinas são proteínas de membrana que transportam:", options: ["Glicose", "Íons Na⁺", "Moléculas de água", "Aminoácidos"], correctIndex: 2, explanation: "Aquaporinas: canais específicos para água. AQP1 (túbulo proximal), AQP2 (ducto coletor, regulada por ADH/vasopressina). Diabetes insipidus nefrogênico: defeito em AQP2 ou receptor V2." },
  { id: 906, topic: "Citologia", question: "A difusão facilitada difere da difusão simples porque:", options: ["Requer ATP", "Utiliza proteínas transportadoras ou canais, sem gasto energético", "Ocorre contra o gradiente", "Transporta apenas íons"], correctIndex: 1, explanation: "Difusão facilitada: a favor do gradiente de concentração, sem gasto de ATP, mas mediada por proteínas carreadoras (GLUT para glicose) ou canais iônicos. Apresenta cinética de saturação." },
  { id: 907, topic: "Citologia", question: "O cotransporte Na⁺/glicose (SGLT1) no intestino delgado é um exemplo de:", options: ["Transporte ativo primário", "Transporte ativo secundário (simporte)", "Difusão simples", "Osmose"], correctIndex: 1, explanation: "SGLT1: simporte Na⁺/glicose — o gradiente de Na⁺ (criado pela Na⁺/K⁺-ATPase) impulsiona a entrada de glicose contra seu gradiente. Transporte ativo secundário, pois depende indiretamente de ATP." },
  { id: 908, topic: "Citologia", question: "A fagocitose é realizada principalmente por:", options: ["Linfócitos T", "Neutrófilos e macrófagos", "Fibroblastos", "Hemácias"], correctIndex: 1, explanation: "Fagocitose: ingestão de partículas grandes (bactérias, debris) por pseudópodos. Fagócitos profissionais: neutrófilos e macrófagos. Formam fagossomo → fusão com lisossomo → fagolisossomo." },
  { id: 909, topic: "Citologia", question: "A exocitose é o processo pelo qual:", options: ["A célula incorpora material extracelular", "Vesículas intracelulares se fundem com a membrana plasmática, liberando conteúdo para o exterior", "O núcleo é expulso", "Ocorre divisão celular"], correctIndex: 1, explanation: "Exocitose: fusão da membrana vesicular com a membrana plasmática, liberando o conteúdo. Pode ser constitutiva (contínua) ou regulada (estímulo-dependente, ex: neurotransmissores, insulina)." },
  { id: 910, topic: "Citologia", question: "Os lipid rafts (balsas lipídicas) da membrana são ricos em:", options: ["Fosfolipídios insaturados", "Esfingolipídios e colesterol, organizados em microdomínios ordenados", "Proteoglicanos", "RNA"], correctIndex: 1, explanation: "Lipid rafts: microdomínios ricos em esfingolipídios, colesterol e proteínas ancoradas a GPI. Funcionam como plataformas de sinalização e tráfego de membrana." },

  // --- ORGANELAS CITOPLASMÁTICAS (16-40) ---
  { id: 911, topic: "Citologia", question: "O retículo endoplasmático rugoso (RER) é especializado em:", options: ["Síntese de lipídios", "Síntese e processamento de proteínas secretoras e de membrana", "Desintoxicação", "Armazenamento de cálcio"], correctIndex: 1, explanation: "O RER possui ribossomos aderidos (confere aspecto 'rugoso'). Sintetiza proteínas com peptídeo-sinal (secretoras, lisossômicas e de membrana). N-glicosilação core inicia no RER." },
  { id: 912, topic: "Citologia", question: "O retículo endoplasmático liso (REL) está relacionado a todas as funções abaixo, EXCETO:", options: ["Síntese de esteroides", "Desintoxicação (citocromo P450)", "Síntese de proteínas de exportação", "Armazenamento/liberação de Ca²⁺"], correctIndex: 2, explanation: "O REL sintetiza lipídios e esteroides, metaboliza drogas/toxinas (citocromo P450), e armazena Ca²⁺ (retículo sarcoplasmático no músculo). A síntese de proteínas de exportação é função do RER." },
  { id: 913, topic: "Citologia", question: "O complexo de Golgi tem como função principal:", options: ["Síntese de DNA", "Modificação, empacotamento e endereçamento de proteínas e lipídios", "Produção de ATP", "Síntese de ribossomos"], correctIndex: 1, explanation: "O Golgi recebe proteínas do RER, realiza O-glicosilação, modifica N-glicanos, adiciona sulfato, e empacota em vesículas com destinos específicos (secreção, membrana, lisossomos)." },
  { id: 914, topic: "Citologia", question: "A face cis do complexo de Golgi está voltada para:", options: ["A membrana plasmática", "O retículo endoplasmático (face de entrada)", "O núcleo", "Os lisossomos"], correctIndex: 1, explanation: "O Golgi é polarizado: face cis (entrada, voltada para o RE) → cisternas medianas → face trans (saída, voltada para membrana plasmática). O transporte ocorre por vesículas entre cisternas." },
  { id: 915, topic: "Citologia", question: "O marcador enzimático dos lisossomos é:", options: ["Citocromo c oxidase", "Fosfatase ácida", "Succinato desidrogenase", "Catalase"], correctIndex: 1, explanation: "A fosfatase ácida é o marcador enzimático clássico dos lisossomos. Os lisossomos contêm ~60 hidrolases ácidas ativas em pH ~5, mantido pela bomba H⁺-ATPase vacuolar." },
  { id: 916, topic: "Citologia", question: "As doenças lisossômicas de depósito são causadas por:", options: ["Excesso de enzimas lisossômicas", "Deficiência de enzimas lisossômicas específicas, levando ao acúmulo de substratos não degradados", "Aumento da biogênese de lisossomos", "Defeito na membrana plasmática"], correctIndex: 1, explanation: "Doenças de depósito: deficiência enzimática → acúmulo de substrato. Ex: Gaucher (glicocerebrosidase), Tay-Sachs (hexosaminidase A), Fabry (α-galactosidase A), Niemann-Pick (esfingomielinase)." },
  { id: 917, topic: "Citologia", question: "A doença de Tay-Sachs resulta da deficiência de:", options: ["Glicocerebrosidase", "Hexosaminidase A, com acúmulo de gangliosídeo GM2", "Esfingomielinase", "α-galactosidase A"], correctIndex: 1, explanation: "Tay-Sachs: deficiência de hexosaminidase A → acúmulo de gangliosídeo GM2 nos neurônios. Autossômica recessiva. Mancha vermelho-cereja na retina. Neurodegeneração fatal." },
  { id: 918, topic: "Citologia", question: "Os peroxissomos são organelas que contêm:", options: ["Hidrolases ácidas", "Catalase e oxidases que metabolizam H₂O₂ e realizam β-oxidação de ácidos graxos de cadeia muito longa", "Ribossomos", "DNA próprio"], correctIndex: 1, explanation: "Peroxissomos: catalase (decompõe H₂O₂), β-oxidação de AG de cadeia muito longa (>C22), metabolismo de ácido úrico. Deficiência: Síndrome de Zellweger (defeito na biogênese peroxissômica)." },
  { id: 919, topic: "Citologia", question: "As mitocôndrias possuem DNA próprio (mtDNA) que é:", options: ["Linear e herdado do pai", "Circular, materno e codifica 37 genes", "Idêntico ao DNA nuclear", "Sem função conhecida"], correctIndex: 1, explanation: "O mtDNA é circular, de herança materna, com 37 genes (13 proteínas da cadeia respiratória, 22 tRNAs, 2 rRNAs). Mutações causam doenças mitocondriais (MELAS, MERRF, neuropatia óptica de Leber)." },
  { id: 920, topic: "Citologia", question: "A cadeia transportadora de elétrons mitocondrial está localizada na:", options: ["Membrana externa", "Membrana interna da mitocôndria (cristas mitocondriais)", "Matriz mitocondrial", "Espaço intermembranas"], correctIndex: 1, explanation: "A cadeia respiratória (complexos I-IV) e a ATP sintase (complexo V) estão na membrana interna mitocondrial. As cristas aumentam a superfície para maior produção de ATP." },
  { id: 921, topic: "Citologia", question: "O ciclo de Krebs (ácido cítrico) ocorre na:", options: ["Membrana interna mitocondrial", "Matriz mitocondrial", "Citoplasma", "Membrana externa"], correctIndex: 1, explanation: "O ciclo de Krebs ocorre na matriz mitocondrial, oxidando acetil-CoA e gerando NADH e FADH₂ que alimentam a cadeia respiratória. Também gera GTP e intermediários biossintéticos." },
  { id: 922, topic: "Citologia", question: "A liberação de citocromo c da mitocôndria desencadeia:", options: ["Síntese de ATP", "Apoptose via via intrínseca (mitocondrial)", "Duplicação do DNA", "Secreção de proteínas"], correctIndex: 1, explanation: "Citocromo c no citoplasma + Apaf-1 → apoptossomo → ativação de caspase-9 (iniciadora) → caspase-3 (efetora) → apoptose. Regulada por proteínas Bcl-2 (anti) e Bax/Bak (pró-apoptóticas)." },
  { id: 923, topic: "Citologia", question: "Os ribossomos livres no citoplasma sintetizam:", options: ["Proteínas de secreção", "Proteínas destinadas ao citoplasma, núcleo, mitocôndrias e peroxissomos", "Exclusivamente enzimas lisossômicas", "Lipídios"], correctIndex: 1, explanation: "Ribossomos livres: sintetizam proteínas solúveis do citosol, proteínas nucleares, mitocondriais e peroxissômicas. Ribossomos do RER: proteínas com peptídeo-sinal (secretoras, lisossômicas, de membrana)." },
  { id: 924, topic: "Citologia", question: "O proteassomo é responsável por:", options: ["Síntese proteica", "Degradação seletiva de proteínas marcadas com ubiquitina", "Transporte de vesículas", "Replicação do DNA"], correctIndex: 1, explanation: "Proteassomo 26S: complexo multicatalítico que degrada proteínas poliubiquitinadas em peptídeos. Regula ciclo celular (ciclinas), elimina proteínas defeituosas. Inibidores (bortezomibe): terapia do mieloma múltiplo." },
  { id: 925, topic: "Citologia", question: "A doença de inclusão celular (I-cell disease) é causada por defeito em:", options: ["Catalase peroxissômica", "Fosforilação de manose-6-fosfato no Golgi, impedindo endereçamento correto de enzimas lisossômicas", "ATP sintase mitocondrial", "Proteassomo"], correctIndex: 1, explanation: "I-cell disease: deficiência de N-acetilglucosamina-1-fosfotransferase → enzimas lisossômicas não recebem marcador M6P → secretadas ao invés de irem para os lisossomos. Acúmulo de substrato." },

  // --- CITOESQUELETO (41-55) ---
  { id: 926, topic: "Citologia", question: "Os microtúbulos são polímeros de:", options: ["Actina", "Dímeros de α e β-tubulina", "Queratina", "Vimentina"], correctIndex: 1, explanation: "Microtúbulos: cilindros de 25 nm formados por 13 protofilamentos de dímeros α/β-tubulina. Polarizados (extremidade + e −). Funções: fuso mitótico, transporte axonal, cílios/flagelos, citoarquitetura." },
  { id: 927, topic: "Citologia", question: "A colchicina atua sobre o citoesqueleto inibindo:", options: ["Polimerização de actina", "Polimerização de microtúbulos, bloqueando a mitose em metáfase", "Filamentos intermediários", "Miosina"], correctIndex: 1, explanation: "A colchicina liga-se à tubulina livre, impedindo a polimerização de microtúbulos e bloqueando o fuso mitótico. Usada no tratamento da gota e na citogenética para cariotipagem (parada em metáfase)." },
  { id: 928, topic: "Citologia", question: "Os filamentos de actina (microfilamentos) possuem diâmetro de:", options: ["25 nm", "10 nm", "7 nm (os mais finos do citoesqueleto)", "50 nm"], correctIndex: 2, explanation: "Microfilamentos de actina: ~7 nm de diâmetro, formados por actina G polimerizada em actina F (dupla hélice). Funções: contração muscular, microvilosidades, anel contrátil na citocinese, migração celular." },
  { id: 929, topic: "Citologia", question: "A faloidina é uma toxina que:", options: ["Despolimeriza microtúbulos", "Estabiliza filamentos de actina, impedindo sua despolimerização", "Degrada DNA", "Inibe ribossomos"], correctIndex: 1, explanation: "Faloidina (Amanita phalloides): liga-se aos filamentos de actina e os estabiliza, impedindo a dinâmica normal do citoesqueleto. Faloidina fluorescente é usada para visualizar actina em microscopia." },
  { id: 930, topic: "Citologia", question: "Os filamentos intermediários diferem de microtúbulos e microfilamentos porque:", options: ["São polarizados", "Não são polarizados e conferem resistência mecânica sem atividade motora direta", "Possuem atividade ATPásica", "São idênticos em todas as células"], correctIndex: 1, explanation: "Filamentos intermediários: ~10 nm, sem polaridade (sem extremidade + ou −), sem atividade motora. Resistência mecânica. Tipos: queratina (epitelial), vimentina (mesênquima), desmina (músculo), GFAP (astrócitos), neurofilamentos (neurônios), lâminas nucleares." },
  { id: 931, topic: "Citologia", question: "A dineína é a proteína motora que se move em direção à:", options: ["Extremidade positiva (+) dos microtúbulos", "Extremidade negativa (−) dos microtúbulos (transporte retrógrado)", "Extremidade positiva (+) dos filamentos de actina", "Membrana plasmática exclusivamente"], correctIndex: 1, explanation: "Dineína: motor molecular que caminha para a extremidade − dos microtúbulos (retrógrado, centrípeto). Cinesina: caminha para a extremidade + (anterógrado, centrífugo). Ambas usam ATP." },
  { id: 932, topic: "Citologia", question: "A cinesina é a proteína motora responsável pelo transporte:", options: ["Retrógrado nos microtúbulos", "Anterógrado nos microtúbulos (da extremidade − para a +)", "De miosina na actina", "De ribossomos no RE"], correctIndex: 1, explanation: "Cinesina: transporte anterógrado nos microtúbulos (do centrossomo/corpo celular → periferia/sinapse). Transporta vesículas, organelas e mRNA. Essencial no transporte axonal anterógrado." },
  { id: 933, topic: "Citologia", question: "O centrossomo é composto por:", options: ["Dois centríolos e material pericentriolar amorfo, organizando microtúbulos", "Ribossomos e RNA", "Filamentos intermediários", "Membranas do Golgi"], correctIndex: 0, explanation: "O centrossomo: 2 centríolos perpendiculares + material pericentriolar (γ-tubulina). É o principal centro organizador de microtúbulos (MTOC). Duplica-se na fase S e organiza o fuso mitótico." },
  { id: 934, topic: "Citologia", question: "A síndrome de Kartagener (discinesia ciliar primária) é causada por defeito em:", options: ["Actina", "Dineína ciliar, afetando a motilidade de cílios", "Queratina", "Laminina"], correctIndex: 1, explanation: "Kartagener: defeito nos braços de dineína dos cílios → imotilidade ciliar. Tríade: situs inversus + bronquiectasias + sinusite crônica. Também causa infertilidade masculina (flagelo imóvel)." },
  { id: 935, topic: "Citologia", question: "As lâminas nucleares (laminas A, B, C) são filamentos intermediários que:", options: ["Formam o citoesqueleto externo", "Revestem a face interna do envelope nuclear, dando suporte estrutural", "Compõem os cílios", "Formam as cristas mitocondriais"], correctIndex: 1, explanation: "As lâminas nucleares formam uma rede na face interna do envelope nuclear. Despolimerizam na mitose (fosforilação por CDK1) e repolimerizam na telófase. Mutação em lamina A: laminopatias (progéria de Hutchinson-Gilford)." },
  { id: 936, topic: "Citologia", question: "A miosina II é a proteína motora essencial para:", options: ["Transporte em microtúbulos", "Contração muscular e citocinese (anel contrátil)", "Polimerização de actina", "Movimentação ciliar"], correctIndex: 1, explanation: "Miosina II: motor molecular que interage com actina, gerando força de contração. No músculo: deslizamento dos filamentos finos sobre grossos. Na citocinese: forma o anel contrátil que divide a célula." },

  // --- NÚCLEO E CROMATINA (56-70) ---
  { id: 937, topic: "Citologia", question: "O envelope nuclear é formado por:", options: ["Uma membrana simples", "Duas membranas (interna e externa) contínuas com o RE, com poros nucleares", "Bicamada lipídica sem poros", "Parede de celulose"], correctIndex: 1, explanation: "Envelope nuclear: membrana externa (contínua com o RER, com ribossomos) + membrana interna (associada às lâminas nucleares) + espaço perinuclear. Poros nucleares: complexos de nucleoporinas (~30 tipos)." },
  { id: 938, topic: "Citologia", question: "Os complexos de poro nuclear permitem a passagem de:", options: ["Apenas íons pequenos", "Moléculas pequenas passivamente e macromoléculas (>40 kDa) por transporte ativo mediado por importinas/exportinas", "DNA cromossômico", "Nada — são estruturais apenas"], correctIndex: 1, explanation: "Poros nucleares: ~3.000/núcleo. Moléculas <40 kDa passam passivamente. Proteínas com NLS (sinal de localização nuclear) são transportadas por importinas + Ran-GTP. Exportinas exportam RNA e proteínas." },
  { id: 939, topic: "Citologia", question: "A eucromatina difere da heterocromatina porque:", options: ["É mais condensada", "É descondensada e transcripcionalmente ativa", "Não contém genes", "É visível apenas em microscopia eletrônica"], correctIndex: 1, explanation: "Eucromatina: descondensada, clara (H&E), ativa transcripcionalmente. Heterocromatina: condensada, escura, inativa. Constitutiva (centrômeros, telômeros) e facultativa (ex: corpúsculo de Barr — Xi)." },
  { id: 940, topic: "Citologia", question: "O corpúsculo de Barr representa:", options: ["Nucléolo", "Um cromossomo X inativado (heterocromatina facultativa) visível em células femininas", "DNA mitocondrial", "Grânulo de secreção"], correctIndex: 1, explanation: "Corpúsculo de Barr: cromossomo X inativado (lyonização), visível como massa de heterocromatina junto ao envelope nuclear. Número de Barr = nº de X − 1. Útil na determinação do sexo cromossômico." },
  { id: 941, topic: "Citologia", question: "O nucléolo é o sítio de:", options: ["Replicação do DNA", "Transcrição do rRNA e montagem das subunidades ribossômicas", "Síntese de DNA mitocondrial", "Empacotamento de histonas"], correctIndex: 1, explanation: "Nucléolo: organiza rRNA 45S (RNA pol I) → processamento em 28S, 18S e 5.8S → montagem com proteínas ribossômicas importadas → subunidades 40S e 60S exportadas ao citoplasma." },
  { id: 942, topic: "Citologia", question: "As histonas são proteínas básicas que:", options: ["Degradam DNA", "Empacotam o DNA em nucleossomos (unidades fundamentais da cromatina)", "Sintetizam RNA", "Transportam proteínas ao núcleo"], correctIndex: 1, explanation: "Nucleossomo: octâmero de histonas (2 cada de H2A, H2B, H3, H4) com ~147 pb de DNA enrolados ~1,65 volta. H1: histona de ligação. Modificações pós-traducionais (acetilação, metilação) regulam expressão gênica (código de histonas)." },
  { id: 943, topic: "Citologia", question: "A acetilação de histonas está geralmente associada a:", options: ["Silenciamento gênico", "Ativação da transcrição por relaxar a cromatina", "Condensação da cromatina", "Replicação do DNA"], correctIndex: 1, explanation: "Acetilação de histonas (HATs): neutraliza cargas positivas → relaxa a interação DNA-histona → eucromatina → ativa transcrição. Desacetilases (HDACs): removem acetil → condensação → silenciamento." },
  { id: 944, topic: "Citologia", question: "Os telômeros são:", options: ["Centrômeros", "Sequências repetitivas (TTAGGG) nas extremidades dos cromossomos, protegendo contra encurtamento", "Sítios de transcrição", "Origens de replicação"], correctIndex: 1, explanation: "Telômeros: repetições TTAGGG nas extremidades cromossômicas. Encurtam a cada divisão (problema da replicação terminal). Telomerase (hTERT): ativa em células-tronco e câncer, repõe telômeros." },
  { id: 945, topic: "Citologia", question: "A metilação do DNA em ilhas CpG de promotores está associada a:", options: ["Ativação da transcrição", "Silenciamento gênico (epigenética)", "Replicação acelerada", "Reparo de DNA"], correctIndex: 1, explanation: "Metilação CpG: adição de grupo metil à citosina por DNA metiltransferases (DNMTs). Promotores metilados → recrutamento de repressores → silenciamento. Padrões aberrantes no câncer (hipermetilação de supressores tumorais)." },
  { id: 946, topic: "Citologia", question: "O complexo coesina mantém:", options: ["Os microtúbulos do fuso", "As cromátides-irmãs unidas até a anáfase", "Os nucleossomos empacotados", "Os ribossomos no RE"], correctIndex: 1, explanation: "Coesina: complexo proteico anelar que mantém cromátides-irmãs juntas após replicação. Na mitose: separase cliva coesina nos centrômeros na anáfase. Na meiose I: coesina é removida dos braços (anáfase I) e dos centrômeros (anáfase II)." },

  // --- CICLO CELULAR (71-85) ---
  { id: 947, topic: "Citologia", question: "As fases do ciclo celular, em ordem, são:", options: ["G1 → S → M → G2", "G1 → S → G2 → M (mitose)", "S → G1 → G2 → M", "M → G1 → G2 → S"], correctIndex: 1, explanation: "Ciclo celular: G1 (crescimento, preparação) → S (síntese de DNA/replicação) → G2 (preparação para mitose) → M (mitose + citocinese). G0: quiescência (neurônios, músculo cardíaco)." },
  { id: 948, topic: "Citologia", question: "O ponto de restrição (R) no ciclo celular ocorre em:", options: ["Final de G2", "Final de G1, após o qual a célula se compromete com a divisão independentemente de mitógenos", "Início de S", "Metáfase"], correctIndex: 1, explanation: "Ponto de restrição (R): final de G1. Antes de R: célula depende de fatores de crescimento. Após R: célula se compromete com a divisão. Regulado por ciclina D/CDK4-6 → fosforilação de Rb → liberação de E2F → transcrição de genes de fase S." },
  { id: 949, topic: "Citologia", question: "A proteína Rb (retinoblastoma) controla o ciclo celular:", options: ["Ativando CDKs", "Sequestrando E2F quando hipofosforilada, bloqueando a progressão G1→S", "Degradando ciclinas", "Fosforilando histonas"], correctIndex: 1, explanation: "Rb hipofosforilado → liga E2F → bloqueia transcrição de genes de fase S. Ciclina D/CDK4-6 + ciclina E/CDK2 → fosforilam Rb → liberam E2F → célula entra em S. Perda de Rb → divisão descontrolada." },
  { id: 950, topic: "Citologia", question: "A proteína p53 é conhecida como 'guardiã do genoma' porque:", options: ["Replica DNA", "Detecta dano ao DNA e ativa parada do ciclo, reparo ou apoptose", "Forma o fuso mitótico", "Sintetiza histonas"], correctIndex: 1, explanation: "p53: fator de transcrição ativado por dano ao DNA. Induz p21 (inibidor de CDK → parada em G1), estimula reparo de DNA. Se dano irreparável → ativa genes pró-apoptóticos (Bax, PUMA). Mutação em >50% dos cânceres." },
  { id: 951, topic: "Citologia", question: "As ciclinas e CDKs (quinases dependentes de ciclinas) regulam o ciclo celular. A ciclina B/CDK1 é essencial para:", options: ["Entrada em G1", "Entrada em mitose (fator promotor de maturação/MPF)", "Fase S", "Saída de G0"], correctIndex: 1, explanation: "Ciclina B/CDK1 (MPF): fosforila substratos que desencadeiam mitose — condensação cromossômica (condensinas), despolimerização do envelope nuclear (laminas), reorganização do citoesqueleto. Pico de atividade na transição G2→M." },
  { id: 952, topic: "Citologia", question: "A fase S do ciclo celular é caracterizada por:", options: ["Condensação dos cromossomos", "Replicação (síntese) do DNA, duplicando o conteúdo de 2n para 4n de DNA", "Separação das cromátides", "Citocinese"], correctIndex: 1, explanation: "Fase S: replicação semiconservativa do DNA. Cada cromossomo passa de 1 cromátide a 2 cromátides-irmãs (unidas por coesina). Centrossomo também se duplica. Duração: ~6-8h na maioria das células." },
  { id: 953, topic: "Citologia", question: "Na mitose, a fase em que os cromossomos se alinham no plano equatorial é:", options: ["Prófase", "Metáfase", "Anáfase", "Telófase"], correctIndex: 1, explanation: "Metáfase: cromossomos condensados se alinham na placa metafásica (equatorial). Cinetócoros ligados a microtúbulos do fuso. Checkpoint do fuso (SAC): verifica se todos os cinetócoros estão corretamente ligados." },
  { id: 954, topic: "Citologia", question: "Na anáfase da mitose ocorre:", options: ["Condensação dos cromossomos", "Separação das cromátides-irmãs por clivagem da coesina pela separase", "Formação do envelope nuclear", "Alinhamento no equador"], correctIndex: 1, explanation: "Anáfase: APC/C (complexo promotor da anáfase) ubiquitina securina → liberação de separase → cliva coesina → cromátides-irmãs migram para polos opostos. Anáfase A (encurtamento) + B (alongamento do fuso)." },
  { id: 955, topic: "Citologia", question: "A citocinese em células animais ocorre por:", options: ["Formação de placa celular", "Constrição do anel contrátil de actina e miosina II (sulco de clivagem)", "Endocitose", "Fragmentação do envelope nuclear"], correctIndex: 1, explanation: "Citocinese animal: anel contrátil de actina + miosina II no plano equatorial → constrição progressiva → sulco de clivagem → abscissão (separação). Células vegetais: formam placa celular (vesículas do Golgi)." },
  { id: 956, topic: "Citologia", question: "A meiose difere da mitose porque:", options: ["Produz células idênticas", "Envolve duas divisões sequenciais, gerando 4 células haploides com recombinação genética", "Não envolve replicação de DNA", "Ocorre em todas as células"], correctIndex: 1, explanation: "Meiose: 2 divisões (I: reducional, separa homólogos; II: equacional, separa cromátides). Crossing-over (prófase I) e segregação independente geram diversidade genética. Resultado: 4 células haploides (n)." },
  { id: 957, topic: "Citologia", question: "O crossing-over (recombinação homóloga) ocorre na:", options: ["Metáfase I", "Prófase I (paquíteno) da meiose", "Anáfase II", "Prófase da mitose"], correctIndex: 1, explanation: "Crossing-over: troca de segmentos entre cromátides de cromossomos homólogos no paquíteno da prófase I. Complexo sinaptonemal media o pareamento. Quiasmas: pontos visíveis de recombinação no diplóteno." },
  { id: 958, topic: "Citologia", question: "A não-disjunção meiótica pode resultar em:", options: ["Células com número normal de cromossomos", "Aneuploidias como trissomia 21 (síndrome de Down)", "Poliploidia normal", "Deleções gênicas apenas"], correctIndex: 1, explanation: "Não-disjunção: falha na separação de cromossomos homólogos (meiose I) ou cromátides-irmãs (meiose II). Resulta em aneuploidia: trissomia 21 (Down), 18 (Edwards), 13 (Patau), monossomia X (Turner)." },
  { id: 959, topic: "Citologia", question: "As células que permanecem em G0 indefinidamente incluem:", options: ["Hepatócitos em condições normais", "Neurônios e cardiomiócitos maduros (células permanentes)", "Células epiteliais intestinais", "Células-tronco hematopoiéticas ativas"], correctIndex: 1, explanation: "Células permanentes (G0 irreversível): neurônios, cardiomiócitos, músculo esquelético (diferenciados terminais). Células estáveis (G0 reversível): hepatócitos, linfócitos (entram em G1 com estímulo). Células lábeis: contínua divisão (epitélio, medula óssea)." },
  { id: 960, topic: "Citologia", question: "O checkpoint do fuso mitótico (SAC) garante que:", options: ["O DNA foi replicado", "Todos os cinetócoros estejam corretamente ligados aos microtúbulos antes da anáfase", "Os telômeros estejam intactos", "A citocinese ocorra corretamente"], correctIndex: 1, explanation: "SAC (Spindle Assembly Checkpoint): proteínas Mad e BubR1 inibem APC/C até que todos os cinetócoros estejam biorientados (amphitelic attachment). Cinetócoros não ligados → sinal 'espere'. Defeito → aneuploidia." },

  // --- SINALIZAÇÃO CELULAR (86-92) ---
  { id: 961, topic: "Citologia", question: "A sinalização autócrina é aquela em que:", options: ["A célula secreta sinais que atuam sobre células distantes", "A célula responde aos próprios sinais que ela mesma produz", "O sinal viaja pela corrente sanguínea", "O sinal passa por junções gap"], correctIndex: 1, explanation: "Autócrina: a célula secreta ligantes que atuam sobre seus próprios receptores. Ex: fatores de crescimento em células tumorais, IL-2 em linfócitos T ativados. Parácrina: células vizinhas. Endócrina: via sangue." },
  { id: 962, topic: "Citologia", question: "Os receptores tirosina-quinase (RTKs) ativam qual via de sinalização intracelular clássica?", options: ["Via Wnt", "Via Ras-MAPK (mitogênica)", "Via Notch", "Via Hedgehog"], correctIndex: 1, explanation: "RTKs: ligante → dimerização → autofosforilação → adaptor (Grb2/SOS) → Ras-GTP → Raf → MEK → ERK (MAPK). Controla proliferação e diferenciação. Mutações em Ras: ~30% dos cânceres." },
  { id: 963, topic: "Citologia", question: "Os receptores acoplados à proteína G (GPCRs) possuem:", options: ["Um domínio transmembranar", "Sete domínios transmembranares e ativam proteínas G heterotriméricas", "Atividade tirosina-quinase", "Localização nuclear"], correctIndex: 1, explanation: "GPCRs: 7 domínios transmembranares. Ligante → troca GDP→GTP na subunidade Gα → ativação de efetores (adenilil-ciclase → cAMP; fosfolipase C → IP3 + DAG). Maior família de receptores de membrana." },
  { id: 964, topic: "Citologia", question: "O segundo mensageiro AMPc (AMP cíclico) é gerado pela:", options: ["Fosfolipase C", "Adenilil-ciclase a partir de ATP", "Guanilil-ciclase", "Proteína quinase C"], correctIndex: 1, explanation: "Adenilil-ciclase: ATP → cAMP. cAMP ativa PKA (proteína quinase A) → fosforila alvos. Ex: adrenalina → receptor β-adrenérgico → Gs → adenilil-ciclase → ↑cAMP → glicogenólise hepática. Fosfodiesterase degrada cAMP." },
  { id: 965, topic: "Citologia", question: "A via de sinalização Notch é ativada por:", options: ["Hormônios circulantes", "Contato direto célula-célula (ligante transmembranar → clivagem → domínio intracelular transloca ao núcleo)", "Fatores secretados", "Luz UV"], correctIndex: 1, explanation: "Notch: receptor transmembranar. Ligante (Delta/Jagged) na célula vizinha → clivagem por γ-secretase → NICD transloca ao núcleo → ativa genes HES/HEY. Regula diferenciação, destino celular e desenvolvimento." },
  { id: 966, topic: "Citologia", question: "A apoptose pela via extrínseca é iniciada por:", options: ["Dano ao DNA", "Ligação de ligantes de morte (FasL, TNF, TRAIL) a receptores de morte na membrana", "Liberação de citocromo c", "Estresse do RE"], correctIndex: 1, explanation: "Via extrínseca: Fas-FasL, TNF-TNFR, TRAIL → recrutamento de FADD → ativação de caspase-8 (iniciadora) → caspase-3 (efetora). Via intrínseca: estresse → Bax/Bak → poro mitocondrial → citocromo c → caspase-9." },
  { id: 967, topic: "Citologia", question: "A autofagia é o processo pelo qual:", options: ["A célula fagocita bactérias", "A célula degrada suas próprias organelas e proteínas em autofagossomos que se fundem com lisossomos", "Ocorre morte celular por necrose", "O DNA é reparado"], correctIndex: 1, explanation: "Autofagia: formação de autofagossomo (dupla membrana) → englobamento de organelas danificadas → fusão com lisossomo (autolisossomo) → degradação e reciclagem. Regulada por mTOR (inibidor) e AMPK (ativador). Importante em estresse nutricional." },

  // --- MORTE CELULAR E TEMAS AVANÇADOS (93-100) ---
  { id: 968, topic: "Citologia", question: "As caspases são:", options: ["Quinases", "Proteases cisteínicas que clivam após resíduos de aspartato, essenciais na apoptose", "Fosfatases", "Ligases"], correctIndex: 1, explanation: "Caspases: cisteíno-proteases (cysteine-aspartate proteases). Iniciadoras (8, 9, 10): ativam efetoras. Efetoras (3, 6, 7): clivam substratos → fragmentação do DNA, blebbing, corpos apoptóticos." },
  { id: 969, topic: "Citologia", question: "A necrose difere da apoptose porque:", options: ["É programada geneticamente", "É uma morte patológica com edema celular, ruptura de membrana e resposta inflamatória", "Gera corpos apoptóticos", "É mediada por caspases"], correctIndex: 1, explanation: "Necrose: morte patológica → edema celular, ruptura de membrana, liberação de DAMPs, inflamação aguda. Apoptose: morte programada → condensação, fragmentação, corpos apoptóticos, sem inflamação." },
  { id: 970, topic: "Citologia", question: "A ferroptose é uma forma de morte celular regulada dependente de:", options: ["Caspases", "Acúmulo de ferro e peroxidação lipídica", "Fragmentação nuclear", "Autofagia"], correctIndex: 1, explanation: "Ferroptose: morte não-apoptótica dependente de ferro → peroxidação lipídica lethal. GPX4 (glutationa peroxidase 4) é o principal protetor. Inibição de GPX4 ou depleção de glutationa → ferroptose. Relevante em neurodegeneração e câncer." },
  { id: 971, topic: "Citologia", question: "O retículo endoplasmático participa da resposta UPR (Unfolded Protein Response) quando:", options: ["Há excesso de ATP", "Proteínas mal dobradas se acumulam no lúmen do RE (estresse do RE)", "O DNA é danificado", "Os ribossomos são degradados"], correctIndex: 1, explanation: "UPR: sensores (IRE1, PERK, ATF6) detectam proteínas mal dobradas → ativam vias para: reduzir tradução, aumentar chaperonas, degradar proteínas (ERAD). Se estresse é irresolvível → apoptose." },
  { id: 972, topic: "Citologia", question: "Os corpos multivesiculares (MVBs) podem se fundir com a membrana plasmática e liberar:", options: ["Lisossomos", "Exossomos (vesículas extracelulares de 30-150 nm)", "Peroxissomos", "Mitocôndrias"], correctIndex: 1, explanation: "MVBs → fusão com membrana → liberação de exossomos no meio extracelular. Exossomos carregam proteínas, lipídios, mRNA e miRNA. Comunicação intercelular, diagnóstico (biópsia líquida) e progressão tumoral." },
  { id: 973, topic: "Citologia", question: "O complexo COP II é responsável pelo transporte vesicular:", options: ["Do Golgi para o RE (retrógrado)", "Do RE para o Golgi (anterógrado)", "Do Golgi para os lisossomos", "Da membrana plasmática para endossomos"], correctIndex: 1, explanation: "COP II: vesículas RE → cis-Golgi (anterógrado). COP I: vesículas Golgi → RE (retrógrado, reciclagem de proteínas residentes do RE). Clatrina: vesículas trans-Golgi → endossomos/membrana plasmática." },
  { id: 974, topic: "Citologia", question: "As proteínas Rab são GTPases que regulam:", options: ["Transcrição gênica", "O direcionamento e fusão de vesículas de transporte intracelular", "A condensação da cromatina", "A replicação do DNA"], correctIndex: 1, explanation: "Rab-GTPases: família de >60 membros. Cada Rab marca compartimentos específicos e regula ancoramento (tethering), docking e fusão de vesículas. Rab5 (endossomo precoce), Rab7 (endossomo tardio), Rab11 (reciclagem)." },
  { id: 975, topic: "Citologia", question: "O spliceossomo é responsável por:", options: ["Replicação do DNA", "Remoção de íntrons e junção de éxons no pré-mRNA (splicing)", "Tradução de proteínas", "Degradação de mRNA"], correctIndex: 1, explanation: "Spliceossomo: complexo de snRNPs (U1, U2, U4, U5, U6) + proteínas. Remove íntrons e une éxons do pré-mRNA. Splicing alternativo: um gene → múltiplas proteínas. Mutações em splice sites → doenças." },
  { id: 976, topic: "Citologia", question: "A tradução (síntese proteica) ocorre em três etapas:", options: ["Transcrição, processamento e exportação", "Iniciação (AUG/Met), elongação (adição de aminoácidos) e terminação (códon de parada)", "Fosforilação, ubiquitinação e degradação", "G1, S e G2"], correctIndex: 1, explanation: "Tradução: iniciação (subunidade 40S + Met-tRNAi + mRNA → reconhece AUG → junta 60S), elongação (tRNAs carregados entram no sítio A, ligação peptídica, translocação), terminação (UAA, UAG, UGA → fatores de liberação)." },
  { id: 977, topic: "Citologia", question: "As chaperonas moleculares (como Hsp70 e Hsp60) auxiliam:", options: ["Na replicação do DNA", "No dobramento correto de proteínas, prevenindo agregação", "Na degradação de lipídios", "Na transcrição de rRNA"], correctIndex: 1, explanation: "Chaperonas: Hsp70 (ligam-se a proteínas nascentes, previnem agregação), Hsp60/GroEL (chaperonina — câmara de dobramento), Hsp90 (maturação de receptores e quinases). Usam ATP. Induzidas por estresse térmico." },
  { id: 978, topic: "Citologia", question: "O sistema ubiquitina-proteassomo é essencial para:", options: ["Síntese de membranas", "Degradação seletiva de proteínas regulatórias (ciclinas, p53, IκB) e proteínas defeituosas", "Transporte axonal", "Produção de ATP"], correctIndex: 1, explanation: "Ubiquitinação: E1 (ativação) → E2 (conjugação) → E3 (ligase, especificidade) → poliubiquitina → proteassomo 26S → degradação. Regula ciclo celular, apoptose, NF-κB. Alvo terapêutico no mieloma (bortezomibe)." },
  { id: 979, topic: "Citologia", question: "O retículo sarcoplasmático é uma forma especializada de REL presente em células:", options: ["Epiteliais", "Musculares, armazenando e liberando Ca²⁺ para contração", "Nervosas", "Hepáticas"], correctIndex: 1, explanation: "Retículo sarcoplasmático: REL especializado do músculo. Armazena Ca²⁺ (bomba SERCA). Estímulo → liberação de Ca²⁺ pelos receptores de rianodina (RyR) → contração. Cisternas terminais formam as tríades." },
  { id: 980, topic: "Citologia", question: "A doença de Gaucher é causada pela deficiência de:", options: ["Hexosaminidase A", "Glicocerebrosidase (β-glicosidase ácida), com acúmulo de glicocerebrosídeo em macrófagos", "Esfingomielinase", "α-galactosidase A"], correctIndex: 1, explanation: "Gaucher: deficiência de glicocerebrosidase → acúmulo de glicocerebrosídeo em macrófagos ('células de Gaucher', citoplasma em papel amassado). Hepatoesplenomegalia, citopenias, dor óssea. Tratamento: terapia de reposição enzimática." },
  { id: 981, topic: "Citologia", question: "Os microRNAs (miRNAs) regulam a expressão gênica por:", options: ["Codificação de proteínas", "Ligação à região 3'UTR do mRNA-alvo, levando à degradação ou inibição da tradução", "Metilação do DNA", "Splicing de íntrons"], correctIndex: 1, explanation: "miRNAs: ~22 nucleotídeos, não codificantes. RISC (complexo silenciador induzido por RNA) + miRNA → liga-se ao mRNA-alvo (complementaridade parcial) → degradação ou repressão traducional. Regulam ~60% dos genes humanos." },
  { id: 982, topic: "Citologia", question: "As tight junctions da célula epitelial são compostas pelas proteínas:", options: ["Caderinas e cateninas", "Claudinas e ocludinas", "Integrinas e talina", "Conexinas"], correctIndex: 1, explanation: "Tight junctions: claudinas (>24 tipos, formam poros seletivos), ocludinas e JAMs. Localizam-se na porção mais apical da membrana lateral. Regulam permeabilidade paracelular. ZO-1/2/3: proteínas de scaffolding que as ancoram à actina." },
  { id: 983, topic: "Citologia", question: "A síndrome de Zellweger é causada por defeito na:", options: ["Biogênese mitocondrial", "Biogênese de peroxissomos (importação de proteínas peroxissômicas)", "Formação de lisossomos", "Montagem de ribossomos"], correctIndex: 1, explanation: "Zellweger: mutação em genes PEX (peroxinas) → ausência de peroxissomos funcionais → acúmulo de AG de cadeia muito longa, ácido fitânico. Autossômica recessiva. Hipotonia, convulsões, hepatomegalia. Fatal na infância." },
  { id: 984, topic: "Citologia", question: "O complexo SNARE é essencial para:", options: ["Replicação do DNA", "Fusão de vesículas de transporte com membranas-alvo", "Síntese de proteínas", "Polimerização de microtúbulos"], correctIndex: 1, explanation: "SNAREs: v-SNARE (vesícula, ex: VAMP) + t-SNARE (alvo, ex: sintaxina + SNAP-25) → formam complexo que aproxima membranas e promove fusão. NSF + α-SNAP reciclam SNAREs. Toxina botulínica cliva SNAREs → paralisia flácida." },
  { id: 985, topic: "Citologia", question: "A progéria de Hutchinson-Gilford é causada por mutação no gene:", options: ["TP53", "LMNA (lamina A/C), produzindo a proteína truncada progerina", "CFTR", "BRCA1"], correctIndex: 1, explanation: "Progéria: mutação em LMNA → progerina (lamina A truncada, farnesilada) → deformação do envelope nuclear → envelhecimento prematuro acelerado. Autossômica dominante de novo." },
  { id: 986, topic: "Citologia", question: "O ciclo celular é inibido pelos CKIs (inibidores de CDKs). A família CIP/KIP inclui:", options: ["p16, p15, p18, p19", "p21, p27 e p57 (inibem múltiplos complexos ciclina-CDK)", "Rb e E2F", "Ciclinas A e B"], correctIndex: 1, explanation: "CIP/KIP: p21 (induzido por p53, inibe amplo espectro de CDKs), p27 (inibido por mitógenos, ativo por sinais anti-proliferativos), p57. Família INK4: p16, p15, p18, p19 (inibem especificamente CDK4/6)." },
  { id: 987, topic: "Citologia", question: "A doença de Niemann-Pick tipo A é causada por deficiência de:", options: ["Hexosaminidase A", "Esfingomielinase ácida, com acúmulo de esfingomielina", "Glicocerebrosidase", "α-iduronidase"], correctIndex: 1, explanation: "Niemann-Pick A: deficiência de esfingomielinase ácida → acúmulo de esfingomielina em macrófagos (células espumosas). Hepatoesplenomegalia, neurodegeneração, mancha vermelho-cereja na retina. Fatal na infância." },
  { id: 988, topic: "Citologia", question: "A polirribossomia (polissomo) refere-se a:", options: ["Múltiplos nucléolos", "Vários ribossomos traduzindo simultaneamente o mesmo mRNA", "Acúmulo de lisossomos", "Duplicação de centrômeros"], correctIndex: 1, explanation: "Polissomo: vários ribossomos ligados ao mesmo mRNA, cada um traduzindo uma cópia da proteína simultaneamente. Aumenta a eficiência da tradução. Visíveis em MET como rosetas ou espirais." },
  { id: 989, topic: "Citologia", question: "A via PI3K/Akt/mTOR é uma via de sinalização que promove:", options: ["Apoptose", "Sobrevivência celular, crescimento e proliferação (frequentemente hiperativada no câncer)", "Diferenciação terminal", "Autofagia exclusivamente"], correctIndex: 1, explanation: "PI3K → PIP3 → Akt (PKB) → mTOR → promove síntese proteica, crescimento celular, inibe apoptose e autofagia. PTEN: fosfatase que antagoniza PI3K (supressor tumoral). Mutação/perda de PTEN → ativação constitutiva." },
  { id: 990, topic: "Citologia", question: "Os corpos de Heinz são inclusões citoplasmáticas em eritrócitos causadas por:", options: ["Acúmulo de ferro", "Precipitação de hemoglobina desnaturada/oxidada (ex: deficiência de G6PD)", "Excesso de glicogênio", "Presença de parasitas"], correctIndex: 1, explanation: "Corpos de Heinz: hemoglobina oxidada precipitada. G6PD deficiente → ↓NADPH → ↓glutationa reduzida → hemoglobina oxida e precipita. Baço remove inclusões (bite cells). Estresse oxidativo (drogas, infecção, fava)." },
  { id: 991, topic: "Citologia", question: "A N-glicosilação de proteínas inicia-se no:", options: ["Citoplasma", "Retículo endoplasmático rugoso, onde um oligossacarídeo pré-formado é transferido ao resíduo de asparagina", "Complexo de Golgi", "Lisossomo"], correctIndex: 1, explanation: "N-glicosilação: oligossacarídeo de 14 açúcares (Glc₃Man₉GlcNAc₂) é transferido do dolicol-fosfato para Asn (sequência Asn-X-Ser/Thr) pela oligossacariltransferase no lúmen do RER. Processamento continua no Golgi." },
  { id: 992, topic: "Citologia", question: "A O-glicosilação de proteínas ocorre principalmente no:", options: ["Retículo endoplasmático rugoso", "Complexo de Golgi, com adição sequencial de açúcares a resíduos de serina ou treonina", "Citoplasma", "Núcleo"], correctIndex: 1, explanation: "O-glicosilação: adição de açúcares (GalNAc, galactose, ácido siálico) a Ser/Thr no Golgi. Importante em mucinas. Diferente da N-glicosilação (que inicia no RER com bloco pré-formado)." },
  { id: 993, topic: "Citologia", question: "As inclusões citoplasmáticas de glicogênio são abundantes em:", options: ["Neurônios", "Hepatócitos e fibras musculares esqueléticas", "Eritrócitos maduros", "Linfócitos"], correctIndex: 1, explanation: "Glicogênio: grânulos citoplasmáticos PAS-positivos, abundantes em hepatócitos (6-10% do peso) e músculo esquelético. Reserva energética. Glicogenoses (ex: Von Gierke, Pompe): defeitos enzimáticos → acúmulo." },
  { id: 994, topic: "Citologia", question: "A doença de Pompe (glicogenose tipo II) é causada por deficiência de:", options: ["Fosforilase hepática", "α-glicosidase ácida (maltase ácida) lisossômica", "Glicose-6-fosfatase", "Enzima ramificadora"], correctIndex: 1, explanation: "Pompe: deficiência de maltase ácida (α-1,4-glicosidase lisossômica) → acúmulo de glicogênio nos lisossomos, especialmente músculo cardíaco e esquelético. Infantil: cardiomegalia maciça. Tratamento: terapia de reposição enzimática." },
  { id: 995, topic: "Citologia", question: "O peptídeo-sinal (sequência-sinal) de uma proteína destinada à secreção:", options: ["É localizado na extremidade C-terminal", "É uma sequência hidrofóbica N-terminal que direciona o ribossomo ao RER via partícula SRP", "É clivado no Golgi", "Não é removido nunca"], correctIndex: 1, explanation: "Peptídeo-sinal: ~16-30 aa hidrofóbicos no N-terminal. Reconhecido pela SRP (partícula de reconhecimento de sinal) → ribossomo ancorado no RER → proteína translocada para o lúmen → sinal clivado pela peptidase-sinal." },

  // =============================================
  // ESTRUTURA CELULAR, ORGANELAS E ORGANIZAÇÃO CELULAR (996-1045) — 50 questões adicionais
  // =============================================

  // --- ULTRAESTRUTURA DA MEMBRANA E DOMÍNIOS CELULARES ---
  { id: 996, topic: "Citologia", question: "A assimetria da bicamada lipídica significa que:", options: ["Ambas as camadas têm composição idêntica", "A camada externa é rica em fosfatidilcolina e esfingomielina, enquanto a interna contém fosfatidilserina e fosfatidiletanolamina", "Apenas proteínas diferem entre as camadas", "O colesterol está presente somente na camada externa"], correctIndex: 1, explanation: "A assimetria é mantida por flipases (citoplasma→), flopases (→extracelular) e escramblases (bidirecional). A fosfatidilserina na face interna, quando exposta na externa, sinaliza apoptose (reconhecida por fagócitos)." },
  { id: 997, topic: "Citologia", question: "As microvilosidades do epitélio intestinal possuem um esqueleto interno de:", options: ["Microtúbulos", "Feixes de filamentos de actina estabilizados por vilina e fimbrina", "Filamentos intermediários de queratina", "Miosina II"], correctIndex: 1, explanation: "Microvilosidades: ~20-30 filamentos de actina paralelos, entrecruzados por vilina e fimbrina. Raiz ancorada na trama terminal (terminal web) de espectrina e miosina II. Aumentam a superfície absortiva ~20x." },
  { id: 998, topic: "Citologia", question: "Os estereocílios diferem dos cílios verdadeiros porque:", options: ["Contêm axonema 9+2", "São prolongamentos longos e imóveis de microvilosidades, sustentados por actina (não por microtúbulos)", "São mais curtos", "Possuem corpo basal"], correctIndex: 1, explanation: "Estereocílios: microvilosidades longas e ramificadas, com esqueleto de actina. Encontrados no epidídimo e células ciliadas do ouvido interno. Não possuem axonema nem motilidade ativa (ao contrário de cílios)." },
  { id: 999, topic: "Citologia", question: "O axonema de um cílio móvel apresenta a organização:", options: ["9+0", "9+2 (nove duplas periféricas de microtúbulos e um par central)", "13 protofilamentos simples", "Filamentos de actina"], correctIndex: 1, explanation: "Axonema 9+2: 9 duplas periféricas (A+B) + 2 microtúbulos centrais. Braços de dineína (entre duplas) geram movimento. Nexinas conectam duplas. Cílios primários (sensoriais): 9+0, sem par central, imóveis." },
  { id: 1000, topic: "Citologia", question: "O corpo basal de um cílio é estruturalmente idêntico a:", options: ["Um ribossomo", "Um centríolo (9 tripletes de microtúbulos, sem par central)", "Um nucleossomo", "Um peroxissomo"], correctIndex: 1, explanation: "O corpo basal tem a mesma estrutura do centríolo: 9 tripletes de microtúbulos (A, B, C) dispostos radialmente, sem par central. O centríolo migra à membrana e origina o corpo basal, a partir do qual cresce o axonema." },
  { id: 1001, topic: "Citologia", question: "A polaridade celular no epitélio é definida por:", options: ["Distribuição uniforme de organelas", "Domínios apical, lateral e basal com composição distinta de proteínas e lipídios de membrana", "Ausência de junções", "Simetria radial"], correctIndex: 1, explanation: "Polaridade epitelial: domínio apical (microvilosidades, secreção), lateral (junções célula-célula: tight junctions, desmossomos, junções gap) e basal (hemidesmossomos, integrinas → lâmina basal). Mantida por tight junctions que impedem difusão lateral de proteínas." },

  // --- ORGANELAS — DETALHES ULTRAESTRUTURAIS ---
  { id: 1002, topic: "Citologia", question: "As cisternas do retículo endoplasmático rugoso são contínuas com:", options: ["A membrana plasmática diretamente", "O espaço perinuclear (membrana externa do envelope nuclear)", "Os lisossomos", "O complexo de Golgi diretamente"], correctIndex: 1, explanation: "A membrana externa do envelope nuclear é contínua com as cisternas do RER e frequentemente possui ribossomos aderidos. Isso permite que proteínas sintetizadas no RER acessem o lúmen perinuclear." },
  { id: 1003, topic: "Citologia", question: "Os ribossomos eucarióticos possuem coeficiente de sedimentação de:", options: ["70S (como procariontes)", "80S, com subunidades 40S e 60S", "100S", "50S e 30S"], correctIndex: 1, explanation: "Ribossomos eucarióticos: 80S (40S + 60S). Procarióticos: 70S (30S + 50S). Ribossomos mitocondriais: 55S (semelhantes aos procarióticos — evidência da teoria endossimbiótica). Antibióticos como cloranfenicol inibem 70S." },
  { id: 1004, topic: "Citologia", question: "O complexo de Golgi é formado por pilhas de:", options: ["Vesículas esféricas sem organização", "Cisternas achatadas e empilhadas (4-8 dictiossomos), com faces cis e trans definidas", "Túbulos ramificados contínuos", "Grânulos eletrodensos"], correctIndex: 1, explanation: "Golgi: 4-8 cisternas achatadas empilhadas (dictiossomos). Face cis (entrada, rede cis-Golgi/CGN) → cisternas medianas → face trans (saída, rede trans-Golgi/TGN). Vesículas COP I e COP II medeiam o tráfego." },
  { id: 1005, topic: "Citologia", question: "A manose-6-fosfato (M6P) é um marcador que direciona enzimas:", options: ["Para a membrana plasmática", "Do Golgi para os lisossomos via receptores de M6P", "Para o núcleo", "Para os peroxissomos"], correctIndex: 1, explanation: "No cis-Golgi, enzimas lisossômicas recebem M6P. No trans-Golgi, receptores de M6P direcionam essas enzimas em vesículas revestidas por clatrina para endossomos tardios → lisossomos. pH ácido libera a enzima do receptor." },
  { id: 1006, topic: "Citologia", question: "As cristas mitocondriais podem ter forma:", options: ["Apenas tubular", "Lamelar (na maioria das células) ou tubular (em células esteroidogênicas)", "Exclusivamente esférica", "Idêntica em todos os tecidos"], correctIndex: 1, explanation: "Cristas lamelares: maioria das células. Cristas tubulares ou vesiculares: células produtoras de esteroides (córtex adrenal, células de Leydig). A morfologia reflete a atividade metabólica e enzimas da membrana interna." },
  { id: 1007, topic: "Citologia", question: "A matriz mitocondrial contém:", options: ["Apenas água e íons", "DNA circular, ribossomos 55S, enzimas do ciclo de Krebs e da β-oxidação", "Citocromo c oxidase", "Histonas e cromatina"], correctIndex: 1, explanation: "A matriz contém: mtDNA circular, mitorribossomos (55S), enzimas do ciclo de Krebs, β-oxidação de ácidos graxos, piruvato desidrogenase. Não possui histonas (o mtDNA é 'nu', associado a TFAM)." },
  { id: 1008, topic: "Citologia", question: "Os lisossomos primários diferem dos secundários porque:", options: ["São maiores", "Ainda não se fundiram com material a ser digerido (contêm apenas hidrolases inativas)", "Não contêm enzimas", "São de origem peroxissômica"], correctIndex: 1, explanation: "Lisossomo primário: recém-formado do Golgi, contém hidrolases ácidas inativas (pH neutro). Secundário: resultado da fusão com fagossomo (heterofagossomo) ou autofagossomo (autolisossomo). Corpo residual: material não digerido." },
  { id: 1009, topic: "Citologia", question: "A enzima catalase nos peroxissomos catalisa a reação:", options: ["Glicólise", "2 H₂O₂ → 2 H₂O + O₂ (decompõe peróxido de hidrogênio)", "Fosforilação oxidativa", "Síntese de colesterol"], correctIndex: 1, explanation: "Catalase: converte H₂O₂ tóxico em H₂O e O₂. Peroxissomos também contêm oxidases que geram H₂O₂ como subproduto. Equilíbrio produção/degradação de H₂O₂ protege contra dano oxidativo." },
  { id: 1010, topic: "Citologia", question: "O retículo endoplasmático liso é particularmente abundante em:", options: ["Linfócitos", "Hepatócitos (desintoxicação) e células esteroidogênicas (síntese hormonal)", "Hemácias", "Neurônios motores"], correctIndex: 1, explanation: "REL abundante: hepatócitos (citocromo P450, metabolismo de drogas/álcool — prolifera com uso crônico), células de Leydig e córtex adrenal (síntese de esteroides), músculo estriado (retículo sarcoplasmático — Ca²⁺)." },

  // --- INCLUSÕES E DEPÓSITOS CITOPLASMÁTICOS ---
  { id: 1011, topic: "Citologia", question: "As gotículas lipídicas citoplasmáticas:", options: ["São delimitadas por dupla membrana", "São envolvidas por uma monocamada de fosfolipídios e perilipinas, sem membrana verdadeira", "São organelas com DNA próprio", "Estão ausentes em adipócitos"], correctIndex: 1, explanation: "Gotículas lipídicas: reserva de triacilgliceróis e ésteres de colesterol. Monocamada de fosfolipídios + perilipinas (regulam lipólise). Adipócitos: uma grande gotícula (unilocular) ou múltiplas (multilocular/tecido adiposo marrom)." },
  { id: 1012, topic: "Citologia", question: "A lipofuscina é um pigmento que se acumula em:", options: ["Células jovens em divisão ativa", "Células pós-mitóticas envelhecidas (neurônios, cardiomiócitos) como resíduo lisossômico", "Eritrócitos", "Células epiteliais intestinais"], correctIndex: 1, explanation: "Lipofuscina: 'pigmento de desgaste'. Material lipídico peroxidado não degradável, acumula-se em lisossomos residuais. Coloração amarelo-acastanhada. Marcador de envelhecimento celular. Não é patológica por si." },
  { id: 1013, topic: "Citologia", question: "Os grânulos de melanina são produzidos nos:", options: ["Lisossomos", "Melanossomos, organelas especializadas derivadas de endossomos nos melanócitos", "Peroxissomos", "Mitocôndrias"], correctIndex: 1, explanation: "Melanossomos: organelas de melanócitos com tirosinase (tirosina → DOPA → melanina). Maturação em 4 estágios. Transferidos aos queratinócitos por secreção citócrina. Albinismo: defeitos em tirosinase ou tráfego de melanossomos." },
  { id: 1014, topic: "Citologia", question: "A hemossiderina é uma forma de depósito intracelular de:", options: ["Cálcio", "Ferro, derivada da degradação parcial da ferritina em macrófagos", "Cobre", "Zinco"], correctIndex: 1, explanation: "Hemossiderina: agregados de ferritina parcialmente degradada, visível como grânulos dourado-acastanhados (H&E). Corada pelo azul da Prússia (reação de Perls). Acúmulo excessivo: hemossiderose (local ou sistêmica)." },

  // --- JUNÇÕES CELULARES E ORGANIZAÇÃO ---
  { id: 1015, topic: "Citologia", question: "Os desmossomos (mácula aderente) são ancorados intracelularmente por:", options: ["Filamentos de actina", "Filamentos intermediários (queratinas no epitélio, desmina no músculo cardíaco)", "Microtúbulos", "Miosina"], correctIndex: 1, explanation: "Desmossomos: caderinas desmossômicas (desmogleína + desmocolina) → placa densa (placoglobina + desmoplaquina) → filamentos intermediários. Conferem resistência mecânica. Pênfigo vulgar: autoanticorpos contra desmogleína 3 → acantólise." },
  { id: 1016, topic: "Citologia", question: "As junções gap (comunicantes) são formadas por:", options: ["Claudinas e ocludinas", "Conexons (hexâmeros de conexinas) que formam canais entre células adjacentes", "Integrinas", "Caderinas"], correctIndex: 1, explanation: "Junções gap: 2 conexons alinhados (um de cada célula) → canal intercelular. Passam íons, segundos mensageiros (cAMP, IP3), metabólitos pequenos (<1 kDa). Essenciais na sincronização cardíaca e no acoplamento elétrico." },
  { id: 1017, topic: "Citologia", question: "Os hemidesmossomos diferem dos desmossomos porque:", options: ["Ligam duas células vizinhas", "Ancoram a célula à lâmina basal (e não a outra célula), usando integrinas α6β4", "Usam caderinas", "São compostos por actina"], correctIndex: 1, explanation: "Hemidesmossomos: integrinas α6β4 + plectina + BP180/BP230 → filamentos intermediários de queratina. Ancoram o epitélio à lâmina basal. Penfigoide bolhoso: autoanticorpos contra BP180/BP230 → separação dermo-epidérmica." },
  { id: 1018, topic: "Citologia", question: "A zônula de adesão (cinturão de adesão) é sustentada por:", options: ["Filamentos intermediários", "Filamentos de actina conectados a caderinas E via cateninas (α, β, p120)", "Microtúbulos", "Conexinas"], correctIndex: 1, explanation: "Zônula de adesão: faixa contínua abaixo das tight junctions. Caderina E (cálcio-dependente) → β-catenina → α-catenina → filamentos de actina. Contração do anel de actina: gera forças na morfogênese e fechamento de feridas." },
  { id: 1019, topic: "Citologia", question: "A lâmina basal é composta principalmente por:", options: ["Queratina e desmina", "Colágeno tipo IV, laminina, nidogênio/entactina e proteoglicanos (perlecano)", "Elastina e fibrilina", "Actina e miosina"], correctIndex: 1, explanation: "Lâmina basal: lâmina lúcida (laminina) + lâmina densa (colágeno IV, nidogênio). Funções: suporte, filtração (glomérulo renal), barreira à invasão tumoral, guia de regeneração. Síndrome de Alport: mutação em colágeno IV." },

  // --- TRÁFEGO VESICULAR E ORGANIZAÇÃO INTRACELULAR ---
  { id: 1020, topic: "Citologia", question: "As vesículas COP I transportam material:", options: ["Do RE para o Golgi (anterógrado)", "Do Golgi de volta para o RE (retrógrado) e entre cisternas do Golgi", "Do Golgi para lisossomos", "Da membrana para endossomos"], correctIndex: 1, explanation: "COP I: transporte retrógrado Golgi → RE (recicla proteínas residentes do RE com sinal KDEL) e entre cisternas do Golgi. COP II: anterógrado RE → Golgi. Clatrina: trans-Golgi → endossomos e membrana → endossomos." },
  { id: 1021, topic: "Citologia", question: "A sequência KDEL é um sinal de:", options: ["Exportação nuclear", "Retenção/recuperação de proteínas residentes do retículo endoplasmático", "Direcionamento ao lisossomo", "Degradação proteassomal"], correctIndex: 1, explanation: "KDEL (Lys-Asp-Glu-Leu): sequência C-terminal de proteínas residentes do RE (BiP, PDI, calreticulina). Se escapam ao Golgi, o receptor KDEL no cis-Golgi as recaptura em vesículas COP I de volta ao RE." },
  { id: 1022, topic: "Citologia", question: "O endossomo precoce se diferencia do endossomo tardio por:", options: ["Localização nuclear", "pH levemente ácido (~6,0), marcador Rab5, e função de triagem (reciclagem vs degradação)", "Conter enzimas lisossômicas maduras", "Estar no RE"], correctIndex: 1, explanation: "Endossomo precoce (pH ~6,0, Rab5): triagem — recicla receptores (via Rab11) ou encaminha para degradação. Endossomo tardio (pH ~5,5, Rab7, M6P-R): recebe enzimas lisossômicas do Golgi → funde com lisossomos." },
  { id: 1023, topic: "Citologia", question: "A via endocítica segue a sequência:", options: ["Lisossomo → endossomo → membrana", "Vesícula endocítica → endossomo precoce → endossomo tardio → lisossomo", "Golgi → RE → membrana", "Núcleo → citoplasma → membrana"], correctIndex: 1, explanation: "Endocitose: invaginação da membrana → vesícula revestida → perda do revestimento → endossomo precoce (triagem) → endossomo tardio (maturação, acidificação) → fusão com lisossomo (degradação)." },

  // --- CITOESQUELETO — DETALHES ADICIONAIS ---
  { id: 1024, topic: "Citologia", question: "A trama terminal (terminal web) do epitélio intestinal é composta por:", options: ["Microtúbulos exclusivamente", "Rede de espectrina, miosina II e filamentos intermediários que ancoram as raízes das microvilosidades", "Colágeno", "Elastina"], correctIndex: 1, explanation: "Trama terminal: rede horizontal sub-apical de espectrina (não eritroide), miosina II e filamentos intermediários. Ancora os feixes de actina das microvilosidades e participa da contração que aproxima as microvilosidades." },
  { id: 1025, topic: "Citologia", question: "Os filamentos intermediários de vimentina são encontrados em células de origem:", options: ["Epitelial", "Mesenquimal (fibroblastos, condrócitos, células endoteliais, leucócitos)", "Nervosa exclusivamente", "Muscular exclusivamente"], correctIndex: 1, explanation: "Vimentina: marcador mesenquimal universal. Fibroblastos, células endoteliais, leucócitos, condrócitos. Em patologia: vimentina positiva sugere origem mesenquimal. Transição epitélio-mesenquimal (EMT): células epiteliais expressam vimentina." },
  { id: 1026, topic: "Citologia", question: "A GFAP (proteína ácida fibrilar glial) é um filamento intermediário específico de:", options: ["Neurônios", "Astrócitos (células gliais)", "Células epiteliais", "Células musculares"], correctIndex: 1, explanation: "GFAP: filamento intermediário tipo III, marcador de astrócitos. Usada em imunohistoquímica para identificar tumores astrocitários (gliomas). Aumenta na gliose reativa (cicatrização do SNC)." },
  { id: 1027, topic: "Citologia", question: "As lâminas nucleares do tipo B diferem das do tipo A porque:", options: ["São maiores", "Estão presentes em todas as células (as lâminas A/C são expressas após diferenciação)", "São citoplasmáticas", "Não são fosforiladas"], correctIndex: 1, explanation: "Lâmina B: expressa em todas as células nucleadas (constitutiva). Lâminas A e C (do gene LMNA): expressas em células diferenciadas. Células embrionárias indiferenciadas possuem apenas lâmina B." },
  { id: 1028, topic: "Citologia", question: "A instabilidade dinâmica dos microtúbulos refere-se a:", options: ["Sua rigidez excessiva", "Alternância entre fases de crescimento e encurtamento rápidos na extremidade (+)", "Estabilidade permanente", "Despolimerização apenas"], correctIndex: 1, explanation: "Instabilidade dinâmica: extremidade (+) alterna entre polimerização (resgate) e despolimerização rápida (catástrofe). Regulada pelo cap de GTP-tubulina. Taxol estabiliza (impede despolimerização); colchicina/vimblastina impedem polimerização." },
  { id: 1029, topic: "Citologia", question: "O taxol (paclitaxel) é um quimioterápico que atua:", options: ["Impedindo a polimerização de microtúbulos", "Estabilizando microtúbulos e impedindo sua despolimerização, bloqueando a mitose", "Inibindo actina", "Degradando DNA"], correctIndex: 1, explanation: "Taxol: liga-se à β-tubulina e estabiliza microtúbulos → impede despolimerização → fuso não se desorganiza → célula presa em metáfase → apoptose. Oposto da colchicina/vimblastina (impedem polimerização). Usado em câncer de mama, ovário, pulmão." },

  // --- NÚCLEO E EXPRESSÃO GÊNICA — MAIS DETALHES ---
  { id: 1030, topic: "Citologia", question: "As regiões organizadoras do nucléolo (NORs) estão localizadas nos cromossomos:", options: ["1, 2, 3, 4 e 5", "13, 14, 15, 21 e 22 (cromossomos acrocêntricos humanos)", "X e Y", "6, 7, 8, 9 e 10"], correctIndex: 1, explanation: "NORs: regiões com genes de rRNA repetidos em tandem, nos braços curtos dos acrocêntricos (13, 14, 15, 21, 22). Coradas por AgNOR (prata). O número/tamanho das NORs reflete atividade transcricional (marcador prognóstico em tumores)." },
  { id: 1031, topic: "Citologia", question: "O nucléolo apresenta três componentes ultraestruturais:", options: ["Membrana, matriz e cristas", "Centro fibrilar (CF), componente fibrilar denso (CFD) e componente granular (CG)", "Lâminas, poros e cromatina", "Cis, mediano e trans"], correctIndex: 1, explanation: "CF: rDNA + RNA pol I (transcrição). CFD: pré-rRNA em processamento. CG: subunidades ribossômicas em montagem (pré-40S e pré-60S). Nucléolos proeminentes indicam alta síntese proteica (neurônios, hepatócitos, células tumorais)." },
  { id: 1032, topic: "Citologia", question: "O transporte de proteínas do citoplasma para o núcleo requer:", options: ["Peptídeo-sinal hidrofóbico", "Sinal de localização nuclear (NLS), importinas e o gradiente de Ran-GTP", "Clatrina", "Vesículas COP II"], correctIndex: 1, explanation: "NLS (sequência rica em Lys/Arg) → reconhecida por importina-α/β → translocação pelo poro nuclear → Ran-GTP no núcleo dissocia o complexo → libera a proteína. Exportação: NES (sinal de exportação) + exportina + Ran-GTP." },
  { id: 1033, topic: "Citologia", question: "A RNA polimerase II é responsável pela transcrição de:", options: ["rRNA", "mRNA (genes codificadores de proteínas) e a maioria dos snRNAs", "tRNA", "rRNA 5S"], correctIndex: 1, explanation: "RNA Pol I: rRNA 45S (nucléolo). RNA Pol II: mRNA e snRNA (nucleoplasma), sensível a α-amanitina. RNA Pol III: tRNA, rRNA 5S e outros RNAs pequenos. A α-amanitina (Amanita) inibe Pol II → falência hepática." },

  // --- ORGANIZAÇÃO DO CITOPLASMA E COMPARTIMENTOS ---
  { id: 1034, topic: "Citologia", question: "O citosol constitui aproximadamente que porcentagem do volume celular?", options: ["10-20%", "~55% do volume celular total", "80-90%", "Menos de 5%"], correctIndex: 1, explanation: "O citosol (fase aquosa do citoplasma, excluindo organelas) ocupa ~55% do volume celular. Contém milhares de enzimas, ribossomos livres, proteassomas, inclusões e o citoesqueleto. pH ~7,2." },
  { id: 1035, topic: "Citologia", question: "Os corpos de Weibel-Palade são grânulos de armazenamento específicos de:", options: ["Plaquetas", "Células endoteliais, contendo fator de von Willebrand e P-selectina", "Mastócitos", "Neutrófilos"], correctIndex: 1, explanation: "Corpos de Weibel-Palade: organelas secretoras de células endoteliais. Armazenam fator de von Willebrand (vWF, adesão plaquetária), P-selectina (recrutamento leucocitário) e endotelina-1. Liberados por estímulo (trombina, histamina)." },
  { id: 1036, topic: "Citologia", question: "Os grânulos azurófilos (primários) dos neutrófilos contêm:", options: ["Lactoferrina e colagenase", "Mieloperoxidase, defensinas, lisozima e elastase", "Apenas histamina", "Fosfatase alcalina"], correctIndex: 1, explanation: "Grânulos azurófilos (primários): mieloperoxidase (sistema MPO-H₂O₂-haleto), defensinas, lisozima, elastase, catepsinas. Grânulos específicos (secundários): lactoferrina, colagenase, lisozima. Terciários: gelatinase." },
  { id: 1037, topic: "Citologia", question: "O acrossomo do espermatozoide é derivado de qual organela?", options: ["Mitocôndria", "Complexo de Golgi, funcionando como um lisossomo modificado", "Retículo endoplasmático", "Peroxissomo"], correctIndex: 1, explanation: "O acrossomo: grande vesícula derivada do Golgi que cobre o núcleo do espermatozoide. Contém hialuronidase, acrosina e proteases que digerem a zona pelúcida do oócito na fecundação (reação acrossômica)." },
  { id: 1038, topic: "Citologia", question: "A teoria endossimbiótica explica a origem de:", options: ["Ribossomos e núcleo", "Mitocôndrias (de α-proteobactérias) e cloroplastos (de cianobactérias)", "Peroxissomos e lisossomos", "Filamentos intermediários"], correctIndex: 1, explanation: "Evidências: mitocôndrias possuem dupla membrana, DNA circular próprio, ribossomos 55S (tipo bacteriano), divisão por fissão binária, sensibilidade a antibióticos bacterianos. Proposta por Lynn Margulis (1967)." },
  { id: 1039, topic: "Citologia", question: "A calreticulina e a calnexina são chaperonas do RE que:", options: ["Degradam proteínas", "Auxiliam no dobramento de glicoproteínas recém-sintetizadas, retendo-as até estarem corretamente dobradas", "Transportam vesículas", "Sintetizam lipídios"], correctIndex: 1, explanation: "Calreticulina (solúvel) e calnexina (transmembranar): chaperonas lectínicas do RE que reconhecem monoglicose nas N-glicanas. Ciclo calnexina/calreticulina: proteínas mal dobradas são reglicosídas pela UGGT e retidas até correção ou ERAD." },
  { id: 1040, topic: "Citologia", question: "O ERAD (degradação associada ao RE) é o processo pelo qual:", options: ["Proteínas são exportadas do RE", "Proteínas mal dobradas irreparáveis são retrotranslocadas do RE ao citosol para degradação pelo proteassomo", "O RE é fragmentado na mitose", "Lipídios são degradados"], correctIndex: 1, explanation: "ERAD: proteínas mal dobradas que não passam no controle de qualidade (ciclo calnexina/calreticulina) → retrotranslocação pelo canal Sec61 → ubiquitinação → degradação pelo proteassomo 26S. Falha no ERAD → estresse do RE → UPR." },

  // --- ESPECIALIZAÇÃO CELULAR E ORGANELAS ---
  { id: 1041, topic: "Citologia", question: "As células parietais gástricas possuem abundância de qual organela para secreção de HCl?", options: ["RER", "Mitocôndrias (fornecem ATP para a H⁺/K⁺-ATPase) e sistema tubulovesicular", "Peroxissomos", "Golgi exclusivamente"], correctIndex: 1, explanation: "Células parietais: numerosas mitocôndrias (~40% do volume) para ATP da bomba H⁺/K⁺-ATPase. Sistema tubulovesicular: reserva de membrana com H⁺/K⁺-ATPase que se funde ao canalículo quando estimulada (histamina, gastrina, acetilcolina)." },
  { id: 1042, topic: "Citologia", question: "Os corpos lamelares dos pneumócitos tipo II contêm:", options: ["Hemoglobina", "Surfactante pulmonar (dipalmitoilfosfatidilcolina/DPPC) armazenado em lamelas concêntricas", "Enzimas digestivas", "Melanina"], correctIndex: 1, explanation: "Corpos lamelares: organelas secretoras dos pneumócitos tipo II, armazenam surfactante em camadas de fosfolipídios. Surfactante reduz tensão superficial alveolar, previne colapso. Deficiência no prematuro → síndrome do desconforto respiratório (SDR)." },
  { id: 1043, topic: "Citologia", question: "Os grânulos de zimogênio das células acinares pancreáticas são:", options: ["Lisossomos", "Vesículas de secreção regulada contendo proenzimas digestivas inativas (tripsinogênio, quimiotripsinogênio)", "Peroxissomos modificados", "Inclusões de glicogênio"], correctIndex: 1, explanation: "Grânulos de zimogênio: grandes vesículas apicais eletrodensas contendo proenzimas (zimogênios) inativas. Exocitose regulada na porção apical. Ativação no duodeno: enteroquinase converte tripsinogênio → tripsina → ativa as demais." },
  { id: 1044, topic: "Citologia", question: "O centríolo possui a estrutura de:", options: ["9+2 microtúbulos", "9 tripletes de microtúbulos (A, B, C) dispostos radialmente, sem par central (9×3+0)", "13 protofilamentos", "Filamentos de actina"], correctIndex: 1, explanation: "Centríolo: cilindro de 9 tripletes de microtúbulos (A: completo, 13 protofilamentos; B e C: incompletos, 10-11). Sem par central (9×3+0). Dois centríolos perpendiculares + material pericentriolar = centrossomo (MTOC)." },
  { id: 1045, topic: "Citologia", question: "A biogênese de peroxissomos pode ocorrer por:", options: ["Brotamento do Golgi apenas", "Divisão (fissão) de peroxissomos pré-existentes e formação de novo a partir do RE", "Fusão de lisossomos", "Endossimbiose"], correctIndex: 1, explanation: "Peroxissomos: biogênese por fissão de peroxissomos existentes (PEX11 medeia) e por formação de novo a partir de vesículas do RE (pré-peroxissomos). Proteínas peroxissômicas são importadas com sinais PTS1 (C-terminal) ou PTS2 (N-terminal) via peroxinas (PEX)." },

  // --- COMPONENTES CELULARES (1046-1095) — 50 questões ---

  // RIBOSSOMOS
  { id: 1046, topic: "Citologia", question: "Os ribossomos eucarióticos possuem coeficiente de sedimentação de:", options: ["70S", "80S (subunidades 40S e 60S)", "50S", "30S"], correctIndex: 1, explanation: "Ribossomos eucarióticos: 80S = subunidade menor 40S (rRNA 18S + ~33 proteínas) + subunidade maior 60S (rRNA 28S, 5.8S, 5S + ~49 proteínas). Procarióticos: 70S (30S + 50S). Mitocôndrias: 55S." },
  { id: 1047, topic: "Citologia", question: "Os polirribossomos (polissomos) livres no citoplasma sintetizam principalmente:", options: ["Proteínas de exportação", "Proteínas citoplasmáticas, nucleares e mitocondriais (sem peptídeo-sinal de RE)", "Proteínas lisossômicas", "Lipídios de membrana"], correctIndex: 1, explanation: "Polissomos livres: traduzem mRNAs sem peptídeo-sinal de RE. Produzem proteínas citosólicas (enzimas glicolíticas), nucleares (histonas) e de organelas (mitocondriais/peroxissômicas com sinais próprios). Polissomos do RER: proteínas com peptídeo-sinal." },
  { id: 1048, topic: "Citologia", question: "O sítio A (aminoacil) do ribossomo é onde:", options: ["Ocorre a formação da ligação peptídica", "O aminoacil-tRNA carregado se liga ao códon do mRNA", "O tRNA desacilado sai do ribossomo", "O mRNA é degradado"], correctIndex: 1, explanation: "Sítios ribossômicos: A (aminoacil) — entrada do aa-tRNA; P (peptidil) — tRNA com cadeia polipeptídica em crescimento, onde ocorre a ligação peptídica pela peptidil-transferase (rRNA 28S); E (exit) — saída do tRNA desacilado." },
  { id: 1049, topic: "Citologia", question: "A subunidade 60S do ribossomo eucariótico contém a atividade de:", options: ["Helicase", "Peptidil-transferase (ribozima catalítica do rRNA 28S)", "Primase", "Topoisomerase"], correctIndex: 1, explanation: "A atividade de peptidil-transferase reside no rRNA 28S da subunidade 60S — é uma ribozima (RNA catalítico). Forma a ligação peptídica entre aminoácidos no sítio P e A. Demonstra que RNA pode ter função enzimática." },

  // LISOSSOMOS
  { id: 1050, topic: "Citologia", question: "O pH ótimo das enzimas lisossômicas (hidrolases ácidas) é aproximadamente:", options: ["7,4", "5,0 (ácido)", "8,5", "6,8"], correctIndex: 1, explanation: "Hidrolases ácidas lisossômicas funcionam em pH ~5,0, mantido pela V-ATPase (bomba de prótons) na membrana lisossômica. pH citosólico ~7,2 protege a célula caso haja ruptura lisossômica (enzimas ficam inativas)." },
  { id: 1051, topic: "Citologia", question: "A marcação de enzimas lisossômicas com manose-6-fosfato (M6P) ocorre:", options: ["No RER", "No complexo de Golgi (rede cis-Golgi)", "Na membrana plasmática", "No núcleo"], correctIndex: 1, explanation: "No cis-Golgi, a N-acetilglicosamina fosfotransferase adiciona fosfato à manose das hidrolases ácidas. Receptores de M6P no trans-Golgi direcionam essas enzimas aos lisossomos via vesículas revestidas por clatrina. Defeito → doença de células I (mucolipidose II)." },
  { id: 1052, topic: "Citologia", question: "A autofagia é o processo pelo qual:", options: ["A célula ingere bactérias", "A célula degrada seus próprios componentes citoplasmáticos em autofagossomos que se fundem com lisossomos", "Ocorre divisão celular", "O núcleo se fragmenta"], correctIndex: 1, explanation: "Autofagia: membrana de isolamento (fagóforo) envolve organelas danificadas/proteínas → autofagossomo → fusão com lisossomo → autolisossomo. Tipos: macroautofagia, microautofagia e autofagia mediada por chaperonas. Regulada por mTOR e proteínas ATG." },
  { id: 1053, topic: "Citologia", question: "A doença de Tay-Sachs resulta da deficiência de:", options: ["Glicose-6-fosfatase", "Hexosaminidase A (acúmulo de gangliosídeo GM2 nos lisossomos)", "Esfingomielinase", "Galactocerebrosidase"], correctIndex: 1, explanation: "Tay-Sachs: deficiência de hexosaminidase A → acúmulo lisossômico de gangliosídeo GM2, especialmente em neurônios. Doença neurodegenerativa fatal na infância. Frequente em judeus Ashkenazi. É uma esfingolipidose." },
  { id: 1054, topic: "Citologia", question: "Os lisossomos secundários resultam da fusão de lisossomos primários com:", options: ["Mitocôndrias", "Fagossomos ou autofagossomos, formando estruturas de digestão ativa", "Centríolos", "Nucléolos"], correctIndex: 1, explanation: "Lisossomo primário (recém-formado, sem substrato) + fagossomo = fagolisossomo; lisossomo primário + autofagossomo = autolisossomo. Ambos são lisossomos secundários com digestão ativa. Resíduos não digeridos → corpos residuais (lipofuscina)." },

  // MITOCÔNDRIAS
  { id: 1055, topic: "Citologia", question: "As cristas mitocondriais são invaginações da:", options: ["Membrana externa", "Membrana interna, aumentando a área para fosforilação oxidativa", "Matriz", "Membrana plasmática"], correctIndex: 1, explanation: "Cristas mitocondriais: pregas da membrana interna que abrigam os complexos da cadeia respiratória (I-IV) e ATP sintase (complexo V). Células com alta demanda energética (cardiomiócitos, hepatócitos) possuem cristas numerosas e densas." },
  { id: 1056, topic: "Citologia", question: "O DNA mitocondrial (mtDNA) humano codifica:", options: ["Todas as proteínas mitocondriais", "13 subunidades da cadeia respiratória, 2 rRNAs e 22 tRNAs", "Histonas mitocondriais", "Enzimas do ciclo de Krebs"], correctIndex: 1, explanation: "mtDNA: circular, 16,5 kb, herança materna. Codifica 13 polipeptídios dos complexos I, III, IV e V; 22 tRNAs e 2 rRNAs (12S e 16S). As ~1.500 proteínas restantes são codificadas pelo DNA nuclear e importadas via TIM/TOM." },
  { id: 1057, topic: "Citologia", question: "A cardiolipina (difosfatidilglicerol) é um fosfolipídio exclusivo de qual membrana?", options: ["Membrana plasmática", "Membrana interna mitocondrial", "Membrana do RE", "Membrana nuclear externa"], correctIndex: 1, explanation: "Cardiolipina: fosfolipídio com 4 cadeias de ácidos graxos, exclusivo da membrana interna mitocondrial. Essencial para atividade do complexo IV (citocromo c oxidase) e ATP sintase. Sua externalização sinaliza apoptose." },
  { id: 1058, topic: "Citologia", question: "Os complexos TOM e TIM na mitocôndria são responsáveis por:", options: ["Síntese de ATP", "Importação de proteínas codificadas pelo núcleo através das membranas externa (TOM) e interna (TIM)", "Replicação do mtDNA", "Fusão mitocondrial"], correctIndex: 1, explanation: "TOM (translocase da membrana externa): reconhece sequências de direcionamento N-terminal (pré-sequência). TIM23: importa proteínas para matriz e membrana interna. TIM22: insere transportadores na membrana interna. Requer potencial de membrana e ATP matricial." },
  { id: 1059, topic: "Citologia", question: "A via intrínseca da apoptose é desencadeada pela liberação de qual molécula mitocondrial?", options: ["ATP", "Citocromo c (do espaço intermembranoso para o citosol)", "NADH", "Acetil-CoA"], correctIndex: 1, explanation: "Via intrínseca: sinais de estresse → abertura de poros na membrana externa por BAX/BAK → liberação de citocromo c → formação do apoptossomo (citocromo c + Apaf-1 + caspase-9) → ativação de caspases efetoras (3, 6, 7). BCL-2 e BCL-XL inibem esse processo." },

  // CITOESQUELETO — MICROFILAMENTOS
  { id: 1060, topic: "Citologia", question: "Os microfilamentos de actina possuem diâmetro aproximado de:", options: ["25 nm", "7 nm", "10 nm", "50 nm"], correctIndex: 1, explanation: "Microfilamentos: ~7 nm de diâmetro, compostos por actina G (globular) que polimeriza em actina F (filamentosa) com polaridade (extremidade + de crescimento rápido, extremidade − de crescimento lento). Presentes no córtex celular, microvilosidades e anel contrátil." },
  { id: 1061, topic: "Citologia", question: "A faloidina é uma toxina que atua no citoesqueleto:", options: ["Despolimerizando microtúbulos", "Estabilizando microfilamentos de actina, impedindo sua despolimerização", "Rompendo filamentos intermediários", "Inibindo dineína"], correctIndex: 1, explanation: "Faloidina (toxina do Amanita phalloides): liga-se à actina F e impede despolimerização, bloqueando a dinâmica do citoesqueleto de actina. Faloidina fluorescente é usada em pesquisa para visualizar filamentos de actina. Citocalasina faz o oposto: impede polimerização." },
  { id: 1062, topic: "Citologia", question: "Nas microvilosidades intestinais, o feixe de microfilamentos de actina é estabilizado por:", options: ["Tubulina", "Vilina e fimbrina (proteínas de empacotamento)", "Desmina", "Queratina"], correctIndex: 1, explanation: "Microvilosidades: núcleo de ~20-30 microfilamentos de actina F paralelos, conectados por vilina e fimbrina (cross-linkers). Na raiz, ancoram-se à trama terminal (terminal web) com espectrina e miosina II. Aumentam área absortiva ~20x." },
  { id: 1063, topic: "Citologia", question: "O anel contrátil durante a citocinese é composto por:", options: ["Microtúbulos e dineína", "Actina F e miosina II", "Filamentos intermediários", "Septinas exclusivamente"], correctIndex: 1, explanation: "Anel contrátil: banda de actina F + miosina II na região equatorial da célula. A miosina II usa ATP para deslizar filamentos de actina, contraindo o anel progressivamente até dividir o citoplasma (clivagem). RhoA/ROCK regulam a formação." },

  // CITOESQUELETO — MICROTÚBULOS
  { id: 1064, topic: "Citologia", question: "Os microtúbulos são polímeros de heterodímeros de:", options: ["Actina e miosina", "α-tubulina e β-tubulina", "Desmina e vimentina", "Queratina ácida e básica"], correctIndex: 1, explanation: "Microtúbulos: cilindros ocos (~25 nm) formados por 13 protofilamentos de dímeros α/β-tubulina. Polares: extremidade + (β-tubulina exposta, crescimento rápido) e extremidade − (α-tubulina, ancorada ao centrossomo). GTP cap estabiliza a extremidade +." },
  { id: 1065, topic: "Citologia", question: "O taxol (paclitaxel) é um fármaco antineoplásico que atua:", options: ["Despolimerizando microtúbulos", "Estabilizando microtúbulos e impedindo sua despolimerização, bloqueando a mitose", "Inibindo a síntese de actina", "Bloqueando topoisomerases"], correctIndex: 1, explanation: "Taxol: estabiliza microtúbulos → impede despolimerização → fuso mitótico não funciona → parada em metáfase → apoptose. Usado em câncer de mama, ovário, pulmão. Vincristina/vimblastina fazem o oposto: impedem polimerização." },
  { id: 1066, topic: "Citologia", question: "A dineína citoplasmática é um motor molecular que se move:", options: ["Em direção à extremidade + dos microtúbulos", "Em direção à extremidade − dos microtúbulos (transporte retrógrado)", "Ao longo de filamentos de actina", "Independente de microtúbulos"], correctIndex: 1, explanation: "Dineína citoplasmática: motor de extremidade − (retrógrado) → transporta vesículas, organelas e cromossomos em direção ao centrossomo/corpo celular. Cinesina: motor de extremidade + (anterógrado) → transporta para periferia. Ambos usam ATP." },
  { id: 1067, topic: "Citologia", question: "O transporte axonal rápido anterógrado é mediado por:", options: ["Dineína", "Cinesina (motor de extremidade +) ao longo de microtúbulos", "Miosina V", "Difusão passiva"], correctIndex: 1, explanation: "Transporte axonal rápido anterógrado: cinesina move vesículas sinápticas e organelas do corpo celular → terminal axonal a ~400 mm/dia. Transporte retrógrado: dineína → corpo celular (~200 mm/dia). Defeitos → neuropatias (Charcot-Marie-Tooth tipo 2)." },

  // CITOESQUELETO — FILAMENTOS INTERMEDIÁRIOS
  { id: 1068, topic: "Citologia", question: "Os filamentos intermediários possuem diâmetro de:", options: ["7 nm", "25 nm", "8-10 nm", "2 nm"], correctIndex: 2, explanation: "Filamentos intermediários: ~10 nm (entre microfilamentos de 7 nm e microtúbulos de 25 nm). São os mais resistentes mecanicamente, não polares, não possuem atividade motora. Fornecem resistência mecânica e estabilidade estrutural." },
  { id: 1069, topic: "Citologia", question: "As citoqueratinas são filamentos intermediários típicos de:", options: ["Células musculares", "Células epiteliais", "Neurônios", "Fibroblastos"], correctIndex: 1, explanation: "Citoqueratinas: tipo I (ácidas) e tipo II (básicas/neutras), sempre formam heteropolímeros. Expressão varia por tipo epitelial (ex: CK7/CK20 na imunohistoquímica diferencia carcinomas). Epidermólise bolhosa simples: mutação em CK5 ou CK14." },
  { id: 1070, topic: "Citologia", question: "A vimentina é um filamento intermediário presente em células de origem:", options: ["Epitelial", "Mesenquimal (fibroblastos, células endoteliais, leucócitos)", "Neural", "Muscular estriada"], correctIndex: 1, explanation: "Vimentina: filamento intermediário tipo III, marcador de células mesenquimais. Coexpressa com desmina no músculo liso. Na imunohistoquímica, diferencia sarcomas (vimentina+) de carcinomas (citoqueratina+) e melanomas (vimentina+ e S-100+)." },
  { id: 1071, topic: "Citologia", question: "Os neurofilamentos (NF-L, NF-M, NF-H) são filamentos intermediários que:", options: ["Formam o fuso mitótico", "Determinam o calibre axonal e a velocidade de condução nervosa", "Compõem os cílios", "Formam a lâmina nuclear"], correctIndex: 1, explanation: "Neurofilamentos: tipo IV. Dispostos longitudinalmente no axônio, seus braços laterais (fosforilados em NF-H e NF-M) determinam o espaçamento e calibre axonal. Maior calibre → maior velocidade de condução. Acúmulo anormal → doenças neurodegenerativas (ELA)." },
  { id: 1072, topic: "Citologia", question: "A GFAP (proteína ácida fibrilar glial) é filamento intermediário específico de:", options: ["Neurônios", "Astrócitos (células gliais do SNC)", "Oligodendrócitos", "Células de Schwann"], correctIndex: 1, explanation: "GFAP: filamento intermediário tipo III dos astrócitos. Marcador imunohistoquímico para gliomas (astrocitomas). Aumenta na gliose reativa (cicatriz glial). Não encontrada em oligodendrócitos (que expressam CNPase) nem em neurônios (neurofilamentos)." },

  // NÚCLEO — ENVOLTÓRIO NUCLEAR
  { id: 1073, topic: "Citologia", question: "O envoltório nuclear é formado por:", options: ["Uma única membrana", "Duas membranas (interna e externa) separadas pelo espaço perinuclear, contínuo com o lúmen do RE", "Três camadas lipídicas", "Apenas lâmina nuclear"], correctIndex: 1, explanation: "Envoltório nuclear: membrana externa (contínua com RE, com ribossomos) + espaço perinuclear (~20-40 nm, contínuo com lúmen do RE) + membrana interna (associada à lâmina nuclear e cromatina). Perfurado por ~3.000-4.000 complexos de poros nucleares." },
  { id: 1074, topic: "Citologia", question: "Os complexos de poros nucleares (NPC) são compostos por:", options: ["Histonas", "Nucleoporinas (~30 tipos diferentes), formando um canal octogonal", "Tubulinas", "Actina exclusivamente"], correctIndex: 1, explanation: "NPC: ~125 MDa, ~30 nucleoporinas diferentes. Estrutura octogonal com anel citoplasmático, anel nuclear (com cesta nuclear) e canal central (~9 nm passivo, ~39 nm ativo). Importação: importinas + Ran-GTP/GDP. FG-nucleoporinas formam barreira seletiva de fase gel/líquida." },
  { id: 1075, topic: "Citologia", question: "A lâmina nuclear é uma rede de filamentos intermediários tipo V composta por:", options: ["Queratinas", "Laminas A, B e C, que fornecem suporte mecânico ao envoltório nuclear", "Vimentina e desmina", "Neurofilamentos"], correctIndex: 1, explanation: "Lâmina nuclear: rede de laminas (tipo A/C do gene LMNA; tipo B1/B2 de genes LMNB1/B2) sob a membrana interna. Funções: suporte mecânico, ancoragem da cromatina, organização nuclear. Mutações LMNA → laminopatias (progéria de Hutchinson-Gilford, distrofia de Emery-Dreifuss)." },
  { id: 1076, topic: "Citologia", question: "O sinal de localização nuclear (NLS) é uma sequência que:", options: ["Dirige proteínas ao RE", "Direciona proteínas ao núcleo, sendo reconhecida por importinas para transporte pelo poro nuclear", "Marca proteínas para degradação", "Ancora proteínas na membrana"], correctIndex: 1, explanation: "NLS: sequência rica em lisinas e argininas (ex: PKKKRKV da SV40). Reconhecida por importina-α/β → complexo se liga ao NPC → transloca via interações com FG-nucleoporinas → no núcleo, Ran-GTP dissocia o complexo → importinas recicladas ao citoplasma." },

  // NÚCLEO — CROMATINA
  { id: 1077, topic: "Citologia", question: "O nucleossomo é a unidade básica da cromatina, composto por:", options: ["DNA enrolado ao redor de 6 histonas", "~147 pb de DNA enrolados 1,65 volta ao redor de um octâmero de histonas (2x H2A, H2B, H3, H4)", "DNA ligado a laminas", "RNA enrolado em proteínas"], correctIndex: 1, explanation: "Nucleossomo: 147 pb de DNA em 1,65 volta ao redor de octâmero de histonas (2 de cada: H2A, H2B, H3, H4). DNA linker (~20-60 pb) entre nucleossomos é associado à histona H1 (linker histone). Compactação: fibra de 10 nm (colar de contas)." },
  { id: 1078, topic: "Citologia", question: "A eucromatina difere da heterocromatina por ser:", options: ["Condensada e inativa", "Descondensada e transcripcionalmente ativa", "Rica em histona H1", "Sempre periférica no núcleo"], correctIndex: 1, explanation: "Eucromatina: descondensada, pálida em ME, rica em genes ativos. Heterocromatina: condensada, eletrodensa, periférica (junto ao envoltório) e perinucleolar. Constitutiva (centrômeros, telômeros, sempre condensada) vs. facultativa (ex: corpúsculo de Barr, X inativado)." },
  { id: 1079, topic: "Citologia", question: "O corpúsculo de Barr é:", options: ["Um nucleossomo especial", "O cromossomo X inativado (heterocromatina facultativa) visível como condensação na periferia nuclear em células femininas", "Um ribossomo nuclear", "Uma organela"], correctIndex: 1, explanation: "Corpúsculo de Barr: X inativado por XIST (RNA não codificante) → heterocromatina facultativa. Mulheres 46,XX: 1 corpúsculo de Barr. Homens 46,XY: nenhum. Klinefelter (47,XXY): 1 corpúsculo. Regra: n° de Barr = n° de X − 1." },
  { id: 1080, topic: "Citologia", question: "A acetilação de histonas (H3K9ac, H3K27ac) geralmente está associada a:", options: ["Silenciamento gênico", "Ativação transcricional (eucromatina aberta)", "Condensação cromossômica", "Reparo de DNA"], correctIndex: 1, explanation: "Acetilação: HATs (histona acetiltransferases) adicionam acetil à lisina → neutraliza carga positiva → enfraquece interação histona-DNA → cromatina aberta → transcrição ativa. Desacetilação por HDACs → condensação → silenciamento. Inibidores de HDAC: uso em oncologia." },

  // NÚCLEO — NUCLÉOLO
  { id: 1081, topic: "Citologia", question: "O nucléolo é o local de:", options: ["Replicação do DNA", "Transcrição do rRNA e montagem das subunidades ribossômicas", "Síntese de mRNA", "Degradação de proteínas"], correctIndex: 1, explanation: "Nucléolo: organiza a transcrição dos rRNAs 45S (pela RNA pol I) → processados em 28S, 18S e 5.8S. Montagem das subunidades ribossômicas: rRNAs + proteínas ribossômicas (importadas do citoplasma). Células com alta síntese proteica (hepatócitos, neurônios) possuem nucléolos proeminentes." },
  { id: 1082, topic: "Citologia", question: "As regiões organizadoras do nucléolo (NOR) estão localizadas nos cromossomos:", options: ["1, 2, 3, 4, 5", "13, 14, 15, 21 e 22 (acrocêntricos, braços curtos)", "X e Y", "6 e 11"], correctIndex: 1, explanation: "NORs: regiões com genes repetidos de rRNA 45S (rDNA), localizadas nos braços curtos dos cromossomos acrocêntricos (13, 14, 15, 21, 22). Coloração com AgNOR marca proteínas argirofílicas associadas → indicador de proliferação celular em patologia." },

  // COMPLEXO DE GOLGI — DETALHES
  { id: 1083, topic: "Citologia", question: "A O-glicosilação de proteínas ocorre predominantemente em qual compartimento?", options: ["RER", "Complexo de Golgi (cisternas medianas e trans)", "Citosol", "Lisossomos"], correctIndex: 1, explanation: "O-glicosilação: adição de açúcares ao grupo OH de serinas/treoninas. Inicia no Golgi (cis → trans), em contraste com N-glicosilação que começa no RER (adição do oligossacarídeo core de 14 açúcares ao N de asparagina). Mucinas são altamente O-glicosiladas." },
  { id: 1084, topic: "Citologia", question: "As vesículas COP I são responsáveis pelo:", options: ["Transporte anterógrado RE → Golgi", "Transporte retrógrado (Golgi → RE e intra-Golgi retrógrado), reciclando proteínas residentes do RE", "Transporte de membrana plasmática a lisossomos", "Exocitose"], correctIndex: 1, explanation: "COP I: retrógrado (trans → cis Golgi, Golgi → RE). Recupera proteínas do RE escapadas (com sinal KDEL/KKXX). COP II: anterógrado (RE → Golgi, em vesículas de transição/ERGIC). Clatrina: trans-Golgi → endossomos/lisossomos e endocitose na membrana plasmática." },
  { id: 1085, topic: "Citologia", question: "A rede trans-Golgi (TGN) é responsável por:", options: ["Receber proteínas do RE", "Classificar e empacotar proteínas em vesículas com destinos distintos (secreção, membrana, lisossomos)", "Sintetizar lipídios", "Replicar DNA"], correctIndex: 1, explanation: "TGN: estação de triagem final. Separa: proteínas de secreção constitutiva (vesículas sem revestimento), secreção regulada (grânulos de secreção), enzimas lisossômicas (via receptor M6P + clatrina), e proteínas de membrana apical vs. basolateral (em células polarizadas)." },

  // RETÍCULO ENDOPLASMÁTICO — DETALHES
  { id: 1086, topic: "Citologia", question: "A resposta a proteínas mal dobradas (UPR) é ativada quando:", options: ["O RE está vazio", "Há acúmulo de proteínas mal dobradas no RE (estresse do RE), ativando sensores IRE1, PERK e ATF6", "O Golgi se fragmenta", "O DNA é danificado"], correctIndex: 1, explanation: "UPR: estresse do RE → sensores (IRE1α: splicing de XBP1; PERK: fosforila eIF2α, reduz tradução global; ATF6: ativa genes de chaperonas). Se irresolvível → apoptose via CHOP. Relevante em diabetes, doenças neurodegenerativas e isquemia." },
  { id: 1087, topic: "Citologia", question: "O retículo sarcoplasmático (RS) é uma forma especializada de:", options: ["Golgi", "Retículo endoplasmático liso, responsável pelo armazenamento e liberação de Ca²⁺ no músculo", "RER", "Peroxissomos"], correctIndex: 1, explanation: "RS: REL especializado do músculo. Armazena Ca²⁺ em alta concentração (calsequestrina). Na contração: sinal → canais rianodina (RyR) abrem → Ca²⁺ para o citosol → troponina C → contração. Relaxamento: SERCA bombeia Ca²⁺ de volta ao RS." },

  // PEROXISSOMOS — DETALHES
  { id: 1088, topic: "Citologia", question: "A principal reação dos peroxissomos envolve:", options: ["Fosforilação oxidativa", "Oxidação de substratos com produção de H₂O₂, decomposto pela catalase", "Síntese proteica", "Glicólise"], correctIndex: 1, explanation: "Peroxissomos: oxidases produzem H₂O₂ como subproduto. Catalase decompõe H₂O₂ → H₂O + ½O₂ ou usa H₂O₂ para oxidar outros substratos (etanol → acetaldeído). Funções: β-oxidação de ácidos graxos de cadeia muito longa (VLCFA), síntese de plasmalógenos." },
  { id: 1089, topic: "Citologia", question: "A adrenoleucodistrofia ligada ao X é causada por defeito em:", options: ["Catalase peroxissômica", "Transportador ABCD1 da membrana peroxissômica (acúmulo de VLCFA)", "Peroxinas de importação", "Enzimas lisossômicas"], correctIndex: 1, explanation: "X-ALD: mutação no gene ABCD1 (Xq28) → defeito no transportador de VLCFA para dentro do peroxissomo → acúmulo de ácidos graxos de cadeia muito longa (C26:0) → desmielinização progressiva no SNC e insuficiência adrenal. Filme 'O Óleo de Lorenzo'." },

  // INCLUSÕES CITOPLASMÁTICAS
  { id: 1090, topic: "Citologia", question: "O glicogênio citoplasmático aparece em ME como:", options: ["Cisternas empilhadas", "Grânulos eletrodensos de ~25-30 nm (partículas β) ou rosetas (partículas α) no citosol", "Vesículas com membrana", "Filamentos"], correctIndex: 1, explanation: "Glicogênio: partículas β individuais (~25-30 nm) ou agrupadas em rosetas (partículas α, ~80-100 nm). Abundante em hepatócitos (manutenção da glicemia) e fibras musculares (energia local). Não têm membrana — são inclusões citoplasmáticas. Glicogenoses: acúmulo anormal." },
  { id: 1091, topic: "Citologia", question: "As gotículas lipídicas (corpos lipídicos) são delimitadas por:", options: ["Bicamada lipídica completa", "Uma monocamada de fosfolipídios com proteínas associadas (perilipinas)", "Membrana tripla", "Sem qualquer envoltório"], correctIndex: 1, explanation: "Gotículas lipídicas: núcleo de ésteres de colesterol e triacilgliceróis envolto por monocamada de fosfolipídios + perilipinas (regulam lipólise). Originam-se do RE. Nos adipócitos: uma grande gotícula (unilocular/branco) ou múltiplas pequenas (multilocular/marrom)." },

  // JUNÇÕES CELULARES — COMPLEMENTO
  { id: 1092, topic: "Citologia", question: "A zonula occludens (tight junction) é formada por quais proteínas transmembranares?", options: ["Caderinas", "Claudinas e ocludinas, que selam o espaço intercelular", "Conexinas", "Integrinas"], correctIndex: 1, explanation: "Tight junctions: claudinas (~27 tipos, determinam seletividade iônica), ocludina e JAMs (moléculas de adesão juncional). Proteínas intracelulares ZO-1/2/3 conectam ao citoesqueleto de actina. Formam barreira paracelular (ex: barreira hematoencefálica, epitélio intestinal)." },
  { id: 1093, topic: "Citologia", question: "Os hemidesmossomos conectam a célula epitelial à:", options: ["Célula vizinha", "Lâmina basal (membrana basal) via integrinas α6β4 e filamentos de queratina", "Matriz extracelular colágena via vimentina", "Outra célula via caderinas"], correctIndex: 1, explanation: "Hemidesmossomos: integrina α6β4 + plectina → filamentos intermediários de queratina. Ancoram epitélio à lâmina basal (laminina-332 e colágeno XVII). Autoanticorpos contra BP180/BP230: penfigoide bolhoso. Contra laminina-332/integrina: penfigoide cicatricial." },

  // MATRIZ EXTRACELULAR CORRELAÇÃO CELULAR
  { id: 1094, topic: "Citologia", question: "As integrinas são receptores de membrana que:", options: ["Transportam glicose", "Conectam o citoesqueleto intracelular à matriz extracelular, mediando adesão e sinalização bidirecional", "Degradam colágeno", "Sintetizam elastina"], correctIndex: 1, explanation: "Integrinas: heterodímeros α/β transmembranares. Ligam fibronectina, laminina, colágeno (na MEC) ao citoesqueleto (talina, vinculina, actina) nos pontos de adesão focal. Sinalização outside-in e inside-out. Regulam migração, proliferação e diferenciação celular." },
  { id: 1095, topic: "Citologia", question: "As caveolas são invaginações da membrana plasmática ricas em:", options: ["Clatrina", "Caveolina e colesterol, formando microdomínios em flask-shape", "Actina e miosina", "Receptor de LDL"], correctIndex: 1, explanation: "Caveolas: invaginações em frasco (~50-80 nm) revestidas por caveolina-1/2/3 e cavina. Ricas em colesterol e esfingolipídios. Funções: endocitose, transcitose (endotélio), mecanossensibilidade, sinalização (eNOS, receptores). Abundantes em células endoteliais, adipócitos e músculo liso." },
];
